/* ----------------------------- helpers ----------------------------- */

const uid = () => Math.random().toString(36).slice(2, 10);
const todayISO = () => new Date().toISOString().slice(0, 10);
const monthKey = (iso) => iso.slice(0, 7);
const fmtSGD = (n) => {
  const sym = SYMBOLS[BASE_CUR] || (BASE_CUR + ' ');
  const dp = ['JPY', 'KRW', 'IDR', 'VND'].includes(BASE_CUR) ? 0 : 2;
  return sym + (n || 0).toLocaleString('en-SG', { minimumFractionDigits: dp, maximumFractionDigits: dp });
};
// Convert an amount in `currency` into the current base currency, using SGD-relative rates.
const toBase = (original, currency, rates) =>
  (original || 0) * ((rates && rates[currency]) ?? 1) / ((rates && rates[BASE_CUR]) ?? 1);
const fmtNum = (n, c) => {
  const sym = SYMBOLS[c] || (c + ' ');
  const dp = ['JPY', 'KRW', 'IDR', 'VND'].includes(c) ? 0 : 2;
  return sym + (n || 0).toLocaleString('en-SG', { minimumFractionDigits: dp, maximumFractionDigits: dp });
};
const daysInMonth = (key) => {
  const [y, m] = key.split('-').map(Number);
  return new Date(y, m, 0).getDate();
};
const prettyDate = (iso) => {
  const d = new Date(iso + 'T00:00:00');
  return d.toLocaleDateString('en-SG', { weekday: 'short', day: 'numeric', month: 'short' });
};
const prettyMonth = (key) => {
  const [y, m] = key.split('-').map(Number);
  return new Date(y, m - 1, 1).toLocaleDateString('en-SG', { month: 'long', year: 'numeric' });
};

// ----- period helpers (week / month / year) -----
const isoDate = (dt) => {
  const y = dt.getFullYear(), m = String(dt.getMonth() + 1).padStart(2, '0'), d = String(dt.getDate()).padStart(2, '0');
  return `${y}-${m}-${d}`;
};
const daysBetween = (a, b) => Math.round((new Date(b + 'T00:00:00') - new Date(a + 'T00:00:00')) / 86400000);
function periodRange(type, anchor) {
  const d = new Date(anchor + 'T00:00:00');
  if (type === 'day') {
    return [anchor, anchor];
  }
  if (type === 'week') {
    const dow = (d.getDay() + 6) % 7; // Monday = 0
    const s = new Date(d); s.setDate(d.getDate() - dow);
    const e = new Date(s); e.setDate(s.getDate() + 6);
    return [isoDate(s), isoDate(e)];
  }
  if (type === 'year') {
    return [`${d.getFullYear()}-01-01`, `${d.getFullYear()}-12-31`];
  }
  // month
  const s = new Date(d.getFullYear(), d.getMonth(), 1);
  const e = new Date(d.getFullYear(), d.getMonth() + 1, 0);
  return [isoDate(s), isoDate(e)];
}
function shiftAnchor(type, anchor, dir) {
  const d = new Date(anchor + 'T00:00:00');
  if (type === 'day') d.setDate(d.getDate() + dir);
  else if (type === 'week') d.setDate(d.getDate() + 7 * dir);
  else if (type === 'year') d.setFullYear(d.getFullYear() + dir);
  else d.setMonth(d.getMonth() + dir);
  return isoDate(d);
}
function periodLabelLong(type, anchor) {
  const [s, e] = periodRange(type, anchor);
  if (type === 'day') {
    return new Date(anchor + 'T00:00:00').toLocaleDateString('en-SG', { weekday: 'short', day: 'numeric', month: 'short', year: 'numeric' });
  }
  if (type === 'year') return s.slice(0, 4);
  if (type === 'month') return prettyMonth(monthKey(anchor));
  const sd = new Date(s + 'T00:00:00'), ed = new Date(e + 'T00:00:00');
  const sm = sd.toLocaleDateString('en-SG', { month: 'short' });
  const em = ed.toLocaleDateString('en-SG', { month: 'short' });
  if (sm === em) return `${sd.getDate()}–${ed.getDate()} ${em} ${ed.getFullYear()}`;
  return `${sd.getDate()} ${sm} – ${ed.getDate()} ${em} ${ed.getFullYear()}`;
}
const capWord = (s) => s.charAt(0).toUpperCase() + s.slice(1);

// Spread an expense across days (e.spreadDays). Returns per-day allocations
// each carrying a share of the SGD amount, starting from the expense date.
function allocations(e) {
  const n = Math.max(1, e.spreadDays || 1);
  if (n === 1) return [{ date: e.date, amt: e.sgd, catId: e.catId, subId: e.subId, tripId: e.tripId, e }];
  const share = e.sgd / n;
  const out = [];
  const d = new Date((e.spreadStart || e.date) + 'T00:00:00');
  for (let i = 0; i < n; i++) {
    out.push({ date: isoDate(d), amt: share, catId: e.catId, subId: e.subId, tripId: e.tripId, e });
    d.setDate(d.getDate() + 1);
  }
  return out;
}
// All allocations (from a list of expenses) whose date passes the predicate.
function allocInRange(expenses, inRange) {
  const out = [];
  for (const e of expenses) for (const a of allocations(e)) if (inRange(a.date)) out.push(a);
  return out;
}

// ----- recurring expenses -----
function addMonthsISO(iso, n) {
  const [y, m, d] = iso.split('-').map(Number);
  const t = new Date(y, m - 1 + n, 1);
  const dim = new Date(t.getFullYear(), t.getMonth() + 1, 0).getDate();
  t.setDate(Math.min(d, dim));
  return isoDate(t);
}
function nextOccurrence(rule, from) {
  // first occurrence strictly after `from` (an iso date), or startDate if from is null
  if (!from) return rule.startDate;
  if (rule.freq === 'weekly') {
    const d = new Date(from + 'T00:00:00'); d.setDate(d.getDate() + 7); return isoDate(d);
  }
  return addMonthsISO(from, 1);
}
// Post any recurring occurrences that are due (up to today). Returns a new data object if anything changed.
function materializeRecurring(data) {
  if (!data || !Array.isArray(data.recurring) || data.recurring.length === 0) return data;
  const today = todayISO();
  const newExpenses = [];
  let changed = false;
  const recurring = data.recurring.map((r) => {
    if (!r.active) return r;
    let last = r.lastPosted || null;
    let occ = last ? nextOccurrence(r, last) : r.startDate;
    let guard = 0;
    while (occ <= today && (!r.endDate || occ <= r.endDate) && guard < 2000) {
      newExpenses.push({
        id: uid(), recurId: r.id, desc: r.desc, original: r.original, currency: r.currency,
        sgd: toBase(r.original, r.currency, data.rates), catId: r.catId, subId: r.subId || null, date: occ,
        spreadDays: 1, spreadStart: null, tripId: r.tripId || null, ts: Date.now(),
      });
      last = occ; occ = nextOccurrence(r, occ); changed = true; guard++;
    }
    return last !== r.lastPosted ? { ...r, lastPosted: last } : r;
  });
  if (!changed) return data;
  return { ...data, recurring, expenses: [...newExpenses.reverse(), ...data.expenses] };
}
function upcomingOf(rule) {
  // next scheduled date strictly after today, or null if the rule has ended
  const today = todayISO();
  let occ = rule.lastPosted ? nextOccurrence(rule, rule.lastPosted) : rule.startDate;
  let guard = 0;
  while (occ <= today && guard < 2000) { occ = nextOccurrence(rule, occ); guard++; }
  if (rule.endDate && occ > rule.endDate) return null;
  return occ;
}
// Group allocations by category for the donut / list.
function groupAllocByCat(allocs, cats) {
  const map = {};
  for (const a of allocs) map[a.catId] = (map[a.catId] || 0) + a.amt;
  return Object.entries(map)
    .map(([id, value]) => {
      const c = cats.find((x) => x.id === id);
      return { id, value, name: c?.name || 'Other', color: c?.color || '#94A3B8' };
    })
    .sort((a, b) => b.value - a.value);
}

// Sort options for expense lists.
const SORTS = {
  amount_desc: { label: 'Largest first', cmp: (a, b) => b.sgd - a.sgd },
  amount_asc: { label: 'Smallest first', cmp: (a, b) => a.sgd - b.sgd },
  date_desc: { label: 'Newest first', cmp: (a, b) => (a.date < b.date ? 1 : a.date > b.date ? -1 : (b.ts || 0) - (a.ts || 0)) },
  date_asc: { label: 'Oldest first', cmp: (a, b) => (a.date > b.date ? 1 : a.date < b.date ? -1 : (a.ts || 0) - (b.ts || 0)) },
};

// Build trend buckets (spread-aware): months for year, days for week/month, none for day.
function buildBuckets(type, start, end, allocs, isCurrent, today) {
  const buckets = [];
  if (type === 'year') {
    const yr = Number(start.slice(0, 4));
    for (let m = 0; m < 12; m++) {
      const mk = `${yr}-${String(m + 1).padStart(2, '0')}`;
      const amt = allocs.filter((a) => monthKey(a.date) === mk).reduce((s, a) => s + a.amt, 0);
      buckets.push({
        kind: 'month', key: mk,
        label: new Date(yr, m, 1).toLocaleDateString('en-SG', { month: 'short' }),
        human: new Date(yr, m, 1).toLocaleDateString('en-SG', { month: 'long', year: 'numeric' }),
        amt: +amt.toFixed(2),
      });
    }
  } else if (type !== 'day') {
    const lastDate = isCurrent ? today : end;
    let d = new Date(start + 'T00:00:00');
    const endD = new Date(lastDate + 'T00:00:00');
    while (d <= endD) {
      const key = isoDate(d);
      const amt = allocs.filter((a) => a.date === key).reduce((s, a) => s + a.amt, 0);
      buckets.push({
        kind: 'day', key,
        label: type === 'week' ? d.toLocaleDateString('en-SG', { weekday: 'short' }) : String(d.getDate()),
        human: prettyDate(key), amt: +amt.toFixed(2),
      });
      d.setDate(d.getDate() + 1);
    }
  }
  return buckets;
}

function SortSelect({ value, onChange }) {
  return (
    <select value={value} onChange={(e) => onChange(e.target.value)}
      className="text-xs font-medium bg-white border border-gray-100 rounded-lg px-2 py-1 outline-none text-gray-500">
      {Object.entries(SORTS).map(([k, o]) => <option key={k} value={k}>{o.label}</option>)}
    </select>
  );
}

function parseEntry(text) {
  const matches = text.match(/\d+(?:[.,]\d{1,2})?/g);
  if (!matches) return { amount: null, desc: text.trim() };
  const last = matches[matches.length - 1];
  const amount = parseFloat(last.replace(',', '.'));
  const idx = text.lastIndexOf(last);
  const desc = (text.slice(0, idx) + text.slice(idx + last.length)).replace(/\s+/g, ' ').trim();
  return { amount, desc };
}

function suggestCategory(desc) {
  const d = ' ' + desc.toLowerCase() + ' ';
  for (const [words, cat, sub] of KEYWORDS) {
    if (words.some((w) => d.includes(w))) return { catId: cat, subId: sub };
  }
  return null;
}

/* ----------------------------- storage ----------------------------- */

const DATA_VERSION = 14;

// One-time, in-place upgrades for data saved by older versions.
function migrate(d) {
  if (!d) return d;
  let v = d.v || 1;
  if (v < 2) {
    // Food becomes a flat category (sub-types removed).
    d.categories = (d.categories || []).map((c) =>
      c.id === 'food' ? { ...c, subs: [] } : c
    );
    v = 2;
  }
  if (v < 3) {
    // Trips gain a custom emoji and colour.
    d.trips = (d.trips || []).map((t, i) => ({
      ...t,
      emoji: t.emoji || '✈️',
      color: t.color || TRIP_COLORS[i % TRIP_COLORS.length],
    }));
    v = 3;
  }
  if (v < 4) {
    // Notes section added.
    if (typeof d.notes !== 'string') d.notes = '';
    v = 4;
  }
  if (v < 5) {
    // Preferred default sort for expense lists.
    if (!d.defaultSort) d.defaultSort = 'amount_desc';
    v = 5;
  }
  if (v < 6) {
    // Recurring expenses + appearance settings.
    if (!Array.isArray(d.recurring)) d.recurring = [];
    if (!d.appearance) d.appearance = { ...DEFAULT_APPEARANCE };
    v = 6;
  }
  if (v < 7) {
    // Optional weekly / monthly / yearly budgets + financial vision page.
    if (!d.budgets) d.budgets = { week: 0, month: d.budget || 0, year: 0 };
    if (!d.goals) d.goals = { ...DEFAULT_GOALS };
    v = 7;
  }
  if (v < 8) {
    // Dark theme removed — move anyone using it back to the default.
    if (d.appearance && d.appearance.theme === 'dark') d.appearance.theme = DEFAULT_APPEARANCE.theme;
    v = 8;
  }
  if (v < 9) {
    // Selectable Notes font.
    if (d.appearance && !d.appearance.noteFont) d.appearance.noteFont = DEFAULT_APPEARANCE.noteFont;
    v = 9;
  }
  if (v < 10) {
    // Notes become multiple tabs with rich text; fold any existing note into the first tab.
    if (!Array.isArray(d.noteTabs)) {
      const t = d.notes || '';
      const html = t ? t.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\n/g, '<br>') : '';
      d.noteTabs = [{ id: uid(), title: 'Notes', html }];
    }
    v = 10;
  }
  if (v < 11) {
    // First-run disclaimer acknowledgement.
    if (typeof d.disclaimerAck !== 'boolean') d.disclaimerAck = false;
    v = 11;
  }
  if (v < 12) {
    // Notes font size + colour.
    if (d.appearance) {
      if (typeof d.appearance.noteSize !== 'number') d.appearance.noteSize = DEFAULT_APPEARANCE.noteSize;
      if (!d.appearance.noteColor) d.appearance.noteColor = DEFAULT_APPEARANCE.noteColor;
    }
    v = 12;
  }
  if (v < 13) {
    if (!d.baseCurrency) d.baseCurrency = 'SGD';
    // Inter was removed from the interface fonts; fall back to Default.
    if (d.appearance && (d.appearance.font === 'inter' || d.appearance.font === 'serif')) {
      d.appearance.font = d.appearance.font === 'serif' ? 'lora' : 'system';
    }
    v = 13;
  }
  if (v < 14) {
    // Add the new default "Restaurants" category for existing users (once).
    if (Array.isArray(d.categories) && !d.categories.some((c) => c.id === 'restaurants' || (c.name || '').toLowerCase() === 'restaurants')) {
      const rest = { id: 'restaurants', name: 'Restaurants', color: '#EA580C', subs: [] };
      const idx = d.categories.findIndex((c) => c.id === 'food');
      if (idx >= 0) d.categories.splice(idx + 1, 0, rest); else d.categories.push(rest);
    }
    v = 14;
  }
  d.v = v;
  return d;
}

// Cloud storage: one JSON row per signed-in user, isolated by Row Level Security.
async function loadStore() {
  try {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return null;
    const { data, error } = await supabase
      .from('app_data').select('data').eq('user_id', user.id).maybeSingle();
    if (error) { console.error('loadStore', error); return null; }
    return data ? data.data : null;
  } catch (e) { console.error('loadStore', e); return null; }
}
async function saveStore(payload) {
  try {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;
    const { error } = await supabase.from('app_data')
      .upsert({ user_id: user.id, data: payload, updated_at: new Date().toISOString() }, { onConflict: 'user_id' });
    if (error) console.error('saveStore', error);
  } catch (e) { console.error('saveStore', e); }
}

const seedData = () => ({
  expenses: [],
  trips: [],
  categories: DEFAULT_CATEGORIES,
  rates: DEFAULT_RATES,
  baseCurrency: 'SGD',
  budget: 0,
  budgets: { week: 0, month: 0, year: 0 },
  activeTripId: null,
  notes: '',
  noteTabs: [{ id: uid(), title: 'Notes', html: '' }],
  disclaimerAck: false,
  defaultSort: 'amount_desc',
  recurring: [],
  appearance: { ...DEFAULT_APPEARANCE },
  goals: { ...DEFAULT_GOALS },
  v: DATA_VERSION,
});

/* ----------------------------- small UI bits ----------------------------- */

function Card({ children, className = '' }) {
  return <div className={'app-card bg-white rounded-2xl border border-gray-100 ' + className}>{children}</div>;
}

function StatTile({ label, value, sub, tone }) {
  return (
    <Card className="p-4 flex-1">
      <div className="text-xs text-gray-400 font-medium">{label}</div>
      <div className="text-xl font-semibold mt-1 tnum" style={{ color: tone || 'var(--ink)' }}>{value}</div>
      {sub && <div className="text-xs text-gray-400 mt-0.5">{sub}</div>}
    </Card>
  );
}

function Dot({ color }) {
  return <span className="inline-block w-2.5 h-2.5 rounded-full shrink-0" style={{ background: color }} />;
}

function todaysQuote() {
  const now = new Date();
  const start = new Date(now.getFullYear(), 0, 0);
  const day = Math.floor((now - start) / 86400000);
  return QUOTES[day % QUOTES.length];
}

function QuoteCard() {
  const q = todaysQuote();
  return (
    <div className="cursive text-center px-4" style={{ color: 'var(--ink)' }}>
      <div style={{ fontSize: 18, lineHeight: '21px', textWrap: 'balance' }}>“{q.q}”</div>
      <div className="mt-1.5" style={{ color: ACCENT, fontSize: 17, fontWeight: 700, lineHeight: '18px' }}>— {q.who}</div>
    </div>
  );
}

/* ----------------------------- main ----------------------------- */

export default function ExpenseTracker({ onSignOut }) {
  const [data, setData] = useState(null);
  const [loaded, setLoaded] = useState(false);
  const [tab, setTab] = useState('home');
  const [editing, setEditing] = useState(null); // expense being edited
  const [undo, setUndo] = useState(null);
  const undoTimer = useRef(null);
  const saveTimer = useRef(null);

  // hydrate
  useEffect(() => {
    let alive = true;
    loadStore().then((d) => {
      if (!alive) return;
      const base = d ? migrate(d) : seedData();
      setData(materializeRecurring(base));
      setLoaded(true);
    });
    return () => { alive = false; };
  }, []);

  // persist (debounced)
  useEffect(() => {
    if (!loaded || !data) return;
    clearTimeout(saveTimer.current);
    saveTimer.current = setTimeout(() => saveStore(data), 350);
  }, [data, loaded]);

  const cats = data?.categories || [];
  const rates = data?.rates || DEFAULT_RATES;
  const activeTrip = useMemo(
    () => (data?.trips || []).find((t) => t.id === data?.activeTripId) || null,
    [data]
  );
  const catById = useMemo(() => Object.fromEntries(cats.map((c) => [c.id, c])), [cats]);

  /* ---------- mutations ---------- */
  const update = (patch) => setData((d) => ({ ...d, ...patch }));

  const addExpense = (e) => {
    update({ expenses: [e, ...data.expenses] });
    setUndo(e);
    clearTimeout(undoTimer.current);
    undoTimer.current = setTimeout(() => setUndo(null), 5000);
  };
  const doUndo = () => { if (undo) { removeExpense(undo.id); setUndo(null); } };
  const addRecurring = (rule) =>
    setData((d) => materializeRecurring({ ...d, recurring: [rule, ...(d.recurring || [])] }));
  const addCategory = (c) => update({ categories: [...data.categories, c] });
  const editExpense = (e) =>
    update({ expenses: data.expenses.map((x) => (x.id === e.id ? e : x)) });
  const removeExpense = (id) =>
    update({ expenses: data.expenses.filter((x) => x.id !== id) });
  const removeExpenses = (ids) => {
    const set = new Set(ids);
    update({ expenses: data.expenses.filter((x) => !set.has(x.id)) });
  };

  if (!loaded || !data) {
    return (
      <div className="min-h-screen flex items-center justify-center text-gray-400 text-sm">
        Loading your money…
      </div>
    );
  }

  const ap = data.appearance || DEFAULT_APPEARANCE;
  const theme = THEMES[ap.theme] || THEMES.green;
  const themeBg = theme.bg;
  ACCENT = theme.accent;
  BASE_CUR = data.baseCurrency || 'SGD';
  const fontStack = (APP_FONTS.find((f) => f.key === ap.font) || APP_FONTS[0]).stack;
  const zoom = (SIZES[ap.size] || SIZES.md).z;
  const isDark = !!theme.dark;

  return (
    <div className="min-h-screen w-full" style={{ background: themeBg, color: isDark ? '#E7EBE8' : '#16271C' }}>
      <style>{`
        @import url('${FONT_IMPORT_URL}');
        .tnum { font-variant-numeric: tabular-nums; }
        * { -webkit-tap-highlight-color: transparent; }
        input, button, select { font-family: inherit; }
        .noscroll::-webkit-scrollbar { display: none; }
        .cursive { font-family: 'Caveat', 'Snell Roundhand', 'Segoe Script', cursive; }
        .note-editor:empty:before { content: attr(data-ph); color: #B8C0BA; pointer-events: none; }
        .note-editor:focus:before { content: none; }
        .mascot { filter: hue-rotate(var(--mascot-hue, 0deg)); }
        [data-ink="strong"] { color: #0A130D; }
        [data-ink="strong"] .text-gray-300 { color: #8A938D !important; }
        [data-ink="strong"] .text-gray-400 { color: #5E6862 !important; }
        [data-ink="strong"] .text-gray-500 { color: #444E48 !important; }
        [data-ink="strong"] .text-gray-600 { color: #333B35 !important; }
        [data-ink="soft"] { color: #3A463F; }
        [data-ink="soft"] .text-gray-300 { color: #D2D7D3 !important; }
        [data-ink="soft"] .text-gray-400 { color: #B4BBB6 !important; }
        [data-ink="soft"] .text-gray-500 { color: #9AA29C !important; }
        [data-ink="soft"] .text-gray-600 { color: #828B85 !important; }
        .app-card { box-shadow: 0 1px 3px rgba(20,40,30,0.05); }
      `}</style>

      {!data.disclaimerAck && (
        <div className="fixed inset-0 flex items-center justify-center p-5" style={{ zIndex: 60, background: 'rgba(0,0,0,0.55)' }}>
          <div className="bg-white rounded-3xl w-full max-w-sm overflow-y-auto noscroll" style={{ maxHeight: '88vh', boxShadow: '0 12px 40px rgba(0,0,0,0.25)' }}>
            <div className="px-5 pt-5 pb-2 text-white" style={{ background: `linear-gradient(135deg, ${ACCENT}, ${ACCENT}cc)` }}>
              <div className="text-lg font-bold leading-snug">HOWDY DEAR FRIEND 💛</div>
              <div className="text-sm font-semibold mt-1 opacity-95">Charlotte here!</div>
            </div>
            <div className="px-5 py-4 space-y-2.5 text-sm text-gray-600" style={{ lineHeight: 1.55 }}>
              <p>I built this lil webapp for fun, so it's not bulletproof! Your data saves to your own cloud account — but things can still break or go weird, and I can't promise to rescue anything you lose. So back up now &amp; then if you're afraid! (Settings → Download backup).</p>
              <p>Use at your own risk &amp; enjoy!! 💛 <span className="text-gray-400">(made with lots of love, and zero warranties HAHA)</span></p>
            </div>
            <div className="px-5 pb-5">
              <button onClick={() => update({ disclaimerAck: true })}
                className="w-full py-3 rounded-2xl text-white font-semibold active:scale-[0.99] transition"
                style={{ background: ACCENT }}>
                I understand — let me in!
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="max-w-md mx-auto pb-24 min-h-screen relative" data-ink={ap.ink} data-theme={isDark ? 'dark' : 'light'}
        style={{ fontFamily: fontStack, zoom, '--mascot-hue': (theme.hue || 0) + 'deg', '--ink': isDark ? '#E7EBE8' : '#1B2420' }}>
        <Header tab={tab} activeTrip={activeTrip} bg={themeBg} dark={isDark} onSettings={() => setTab('settings')} />

        <div className="px-4">
          {tab === 'home' && (
            <HomeTab
              data={data} cats={cats} rates={rates} activeTrip={activeTrip}
              catById={catById} onAdd={addExpense} onAddRecurring={addRecurring} onAddCategory={addCategory} onEdit={setEditing}
            />
          )}
          {tab === 'insights' && (
            <InsightsTab data={data} cats={cats} catById={catById} activeTrip={activeTrip} onEdit={setEditing} />
          )}
          {tab === 'trips' && (
            <TripsTab data={data} cats={cats} catById={catById} rates={rates} update={update} setTab={setTab} />
          )}
          {tab === 'history' && (
            <HistoryTab data={data} cats={cats} catById={catById} onEdit={setEditing} onDelete={removeExpense} onDeleteMany={removeExpenses} />
          )}
          {tab === 'notes' && (
            <NotesTab noteTabs={data.noteTabs} onSaveTabs={(t) => update({ noteTabs: t })}
              goals={data.goals || DEFAULT_GOALS} onSaveGoals={(g) => update({ goals: g })}
              noteFont={(data.appearance || DEFAULT_APPEARANCE).noteFont || 'caveat'}
              noteSize={(data.appearance || DEFAULT_APPEARANCE).noteSize || 19}
              noteColor={(data.appearance || DEFAULT_APPEARANCE).noteColor || '#3A3A3A'}
              onSetNote={(patch) => update({ appearance: { ...(data.appearance || DEFAULT_APPEARANCE), ...patch } })} />
          )}
          {tab === 'settings' && (
            <SettingsTab data={data} update={update} setData={setData} onSignOut={onSignOut} />
          )}
        </div>

        {editing && (
          <EditSheet
            expense={editing} cats={cats} rates={rates} trips={data.trips}
            onClose={() => setEditing(null)}
            onSave={(e) => { editExpense(e); setEditing(null); }}
            onDelete={(id) => { removeExpense(id); setEditing(null); }}
          />
        )}
      </div>

      {undo && (
        <div className="fixed left-1/2 -translate-x-1/2 z-40 w-full max-w-md px-4" style={{ bottom: 84 }}>
          <div className="flex items-center justify-between gap-3 px-4 py-3 rounded-2xl text-white"
            style={{ background: '#1B2420', boxShadow: '0 6px 20px rgba(0,0,0,0.18)' }}>
            <span className="text-sm">Expense added</span>
            <button onClick={doUndo} className="text-sm font-semibold underline">Undo</button>
          </div>
        </div>
      )}

      <BottomNav tab={tab} setTab={setTab} />
    </div>
  );
}

/* ----------------------------- header ----------------------------- */

function Header({ tab, activeTrip, bg, onSettings }) {
  const titles = { home: 'Add expense', insights: 'Insights', trips: 'Trips', history: 'History', notes: 'Notes', settings: 'Settings' };
  const logoRef = useRef(null);
  const timers = useRef([]);
  const chaseRef = useRef(0);
  const [fly, setFly] = useState(null);      // { x, y, s, rz, ry, dur, ease } or null
  const [rain, setRain] = useState(false);
  const [chase, setChase] = useState(0);
  const [burst, setBurst] = useState(null);  // explosion particles
  const [orbit, setOrbit] = useState(false); // orbiting emojis
  const [bubble, setBubble] = useState(null);// little speech emoji above the coin
  const [rainSet, setRainSet] = useState(['🪙']);
  const makeBurst = () => {
    const ic = ['💥', '💰', '🪙', '✨', '🤑', '💸', '🎉', '⭐'];
    return Array.from({ length: 24 }, (_, i) => {
      const a = (i / 24) * 2 * Math.PI + Math.random() * 0.35;
      const d = 130 + Math.random() * 200;
      return { e: ic[i % ic.length], bx: Math.round(Math.cos(a) * d), by: Math.round(Math.sin(a) * d), rot: Math.round(Math.random() * 360), dur: (0.85 + Math.random() * 0.5).toFixed(2), size: Math.round(22 + Math.random() * 18) };
    });
  };

  const W = () => window.innerWidth, H = () => window.innerHeight;
  const home = () => {
    const r = logoRef.current && logoRef.current.getBoundingClientRect();
    return r ? { x: r.left + r.width / 2, y: r.top + r.height / 2 } : { x: 36, y: 40 };
  };
  const clearTimers = () => { timers.current.forEach(clearTimeout); timers.current = []; };
  const at = (ms, fn) => timers.current.push(setTimeout(fn, ms));
  useEffect(() => () => clearTimers(), []);

  const from = () => { const h = home(); setFly({ x: h.x, y: h.y, s: 1, rz: 0, ry: 0, dur: 0.01, ease: 'linear' }); };
  const end = () => {
    chaseRef.current = 0; setChase(0); setOrbit(false); setBubble(null);
    const h = home();
    setFly({ x: h.x, y: h.y, s: 1, rz: 0, ry: 0, dur: 0.45, ease: 'cubic-bezier(.34,1.56,.64,1)' });
    at(470, () => setFly(null));
  };
  const jumpChase = () => {
    const m = 80, x = m + Math.random() * (W() - 2 * m), y = 150 + Math.random() * (H() - 230);
    setFly({ x, y, s: 1.5, rz: Math.random() * 30 - 15, ry: 0, dur: 0.32, ease: 'cubic-bezier(.34,1.56,.64,1)' });
  };
  const onCoinClick = (e) => {
    e.stopPropagation();
    if (chaseRef.current <= 0) return;
    const n = chaseRef.current - 1; chaseRef.current = n; setChase(n);
    if (n > 0) jumpChase(); else end();
  };

  const fire = {
    giantSpin: () => {
      from();
      at(20, () => setFly((f) => ({ ...f, x: W() / 2, y: H() / 2, s: 6, ry: 720, dur: 1.1, ease: 'cubic-bezier(.2,.8,.2,1)' })));
      at(1150, () => setFly((f) => ({ ...f, ry: 1800, dur: 0.8, ease: 'linear' })));
      at(1980, () => setFly((f) => ({ ...f, ry: 2200, dur: 0.4, ease: 'ease-out' })));
      at(2420, end);
    },
    bounceCorners: () => {
      from();
      const m = 70, pts = [[m, m], [W() - m, m], [W() - m, H() - m], [m, H() - m]];
      at(20, () => setFly((f) => ({ ...f, x: W() / 2, y: H() / 2, s: 2.2, dur: 0.3, ease: 'ease-out' })));
      let t = 360, rz = 0;
      for (let i = 0; i < 8; i++) {
        const [px, py] = pts[i % 4]; rz += 360; const X = px, Y = py, R = rz;
        at(t, () => setFly((f) => ({ ...f, x: X, y: Y, rz: R, dur: 0.42, ease: 'ease-in-out' }))); t += 440;
      }
      at(t, end);
    },
    rocketRain: () => {
      from();
      at(20, () => setFly((f) => ({ ...f, x: W() / 2, y: -260, s: 1.9, ry: 900, dur: 0.5, ease: 'ease-in' })));
      at(540, () => { setFly(null); setRain(true); });
      at(2600, () => {
        setRain(false);
        setFly({ x: home().x, y: -60, s: 1, rz: 0, ry: 0, dur: 0.01, ease: 'linear' });
        at(40, () => setFly((f) => ({ ...f, y: home().y, dur: 0.5, ease: 'cubic-bezier(.34,1.56,.64,1)' })));
        at(560, () => setFly(null));
      });
    },
    rollAcross: () => {
      from();
      const by = H() - 70;
      at(20, () => setFly((f) => ({ ...f, x: 60, y: by, s: 1.7, dur: 0.35, ease: 'ease-out' })));
      at(420, () => setFly((f) => ({ ...f, x: W() - 60, rz: 1440, dur: 1.1, ease: 'ease-in-out' })));
      at(1560, () => setFly((f) => ({ ...f, x: 60, rz: 2880, dur: 1.1, ease: 'ease-in-out' })));
      at(2700, end);
    },
    explode: () => {
      from();
      at(20, () => setFly((f) => ({ ...f, x: W() / 2, y: H() / 2, s: 3, ry: 360, dur: 0.5, ease: 'ease-out' })));
      at(560, () => { setFly((f) => ({ ...f, s: 0.01, dur: 0.12, ease: 'ease-in' })); setBurst(makeBurst()); });
      at(900, () => setFly((f) => ({ ...f, x: home().x, y: home().y, s: 1, ry: 0, dur: 0.55, ease: 'cubic-bezier(.34,1.56,.64,1)' })));
      at(1480, () => setFly(null));
      at(1500, () => setBurst(null));
    },
    orbitStars: () => {
      from();
      at(20, () => setFly((f) => ({ ...f, x: W() / 2, y: H() / 2, s: 2.4, ry: 720, dur: 0.6, ease: 'ease-out' })));
      at(620, () => { setOrbit(true); setFly((f) => ({ ...f, ry: 1440, dur: 2, ease: 'linear' })); });
      at(2700, () => setOrbit(false));
      at(2720, end);
    },
    escape: () => {
      from();
      at(20, () => setFly((f) => ({ ...f, x: W() + 90, y: H() / 2, s: 1.6, rz: 720, dur: 0.5, ease: 'ease-in' })));
      at(640, () => { setBubble('🫣'); setFly((f) => ({ ...f, x: W() - 34, dur: 0.3, ease: 'ease-out' })); });
      at(1080, () => { setBubble(null); setFly((f) => ({ ...f, x: W() + 90, dur: 0.3, ease: 'ease-in' })); });
      at(1440, () => setFly((f) => ({ ...f, x: -90, y: H() / 2, dur: 0.01, ease: 'linear' })));
      at(1500, () => { setBubble('😏'); setFly((f) => ({ ...f, x: 34, dur: 0.3, ease: 'ease-out' })); });
      at(1940, () => { setBubble(null); setFly((f) => ({ ...f, x: -90, dur: 0.3, ease: 'ease-in' })); });
      at(2340, end);
    },
    dizzy: () => {
      from();
      at(20, () => { setFly((f) => ({ ...f, x: W() / 2, y: H() / 2, s: 2.2, dur: 0.4, ease: 'ease-out' })); setBubble('😵‍💫'); });
      let t = 460;
      for (let i = 0; i < 7; i++) { const R = (i % 2 ? 1 : -1) * (18 + Math.random() * 22); at(t, () => setFly((f) => ({ ...f, rz: R, ry: (f.ry || 0) + 220, dur: 0.22, ease: 'ease-in-out' }))); t += 230; }
      at(t, () => { setBubble('😅'); setFly((f) => ({ ...f, rz: 0, dur: 0.35, ease: 'ease-out' })); });
      at(t + 420, () => setBubble(null));
      at(t + 440, end);
    },
    confetti: () => {
      from();
      setRainSet(['🎉', '✨', '💰', '⭐', '🪙', '💸', '🥳', '🎊']);
      at(20, () => setFly((f) => ({ ...f, x: W() / 2, y: H() / 2, s: 2.6, ry: 1080, dur: 1.2, ease: 'ease-out' })));
      at(120, () => setRain(true));
      at(1300, () => setFly((f) => ({ ...f, ry: 1800, dur: 0.9, ease: 'linear' })));
      at(2500, () => { setRain(false); setRainSet(['🪙']); });
      at(2520, end);
    },
    chase: () => {
      chaseRef.current = 3; setChase(3); from();
      at(20, jumpChase);
      at(11000, () => { if (chaseRef.current > 0) end(); });
    },
  };
  const start = () => {
    if (fly || burst || orbit) return; // let the current gag finish — no stopping it
    clearTimers();
    const keys = Object.keys(fire);
    fire[keys[Math.floor(Math.random() * keys.length)]]();
  };

  const rainPieces = useMemo(() => (rain ? Array.from({ length: 24 }, () => ({
    e: rainSet[Math.floor(Math.random() * rainSet.length)],
    left: +(Math.random() * 100).toFixed(2),
    delay: (Math.random() * 0.8).toFixed(2),
    dur: (1.6 + Math.random() * 1.4).toFixed(2),
    size: Math.round(20 + Math.random() * 22),
    rot: Math.round(-40 + Math.random() * 80),
  })) : []), [rain, rainSet]);

  return (
    <>
    <div className="sticky top-0 z-20 px-4 pt-5 pb-3" style={{ background: bg || '#EDF4ED' }}>
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <button ref={logoRef} onClick={start} aria-label="tap the coin"
            className="shrink-0 active:scale-90 transition" style={{ lineHeight: 0 }}>
            <img src={LOGO} alt="logo" className="mascot w-10 h-10" style={{ objectFit: 'contain', opacity: (fly || rain || burst || orbit) ? 0 : 1 }} />
          </button>
          <div>
            <div className="text-xs text-gray-400 font-medium">
              {tab === 'notes'
                ? 'Private notebook'
                : (activeTrip ? `${activeTrip.emoji || '✈️'} On a trip · ${activeTrip.name}` : 'A Kuekadoodledoo Expense Tracker')}
            </div>
            <h1 className="text-2xl font-semibold tracking-tight">{titles[tab]}</h1>
          </div>
        </div>
        {tab !== 'settings' && (
          <button onClick={onSettings} className="p-2 rounded-full bg-white border border-gray-100 text-gray-500 active:scale-95 transition">
            <SettingsIcon size={18} />
          </button>
        )}
      </div>
    </div>

    {(fly || rain || burst || orbit) && (
      <div className="fixed inset-0 pointer-events-none" style={{ zIndex: 60, overflow: 'hidden' }}>
        <style>{'@keyframes coinRain{0%{transform:translateY(-12vh) rotate(0)}100%{transform:translateY(112vh) rotate(var(--r,40deg))}}@keyframes coinBurst{0%{transform:translate(-50%,-50%) scale(0.3);opacity:0}15%{opacity:1}100%{transform:translate(calc(-50% + var(--bx)),calc(-50% + var(--by))) scale(1) rotate(var(--br));opacity:0}}@keyframes coinSpinRing{from{transform:translate(-50%,-50%) rotate(0)}to{transform:translate(-50%,-50%) rotate(360deg)}}'}</style>
        {rainPieces.map((p, i) => (
          <span key={i} style={{ position: 'absolute', top: 0, left: p.left + '%', fontSize: p.size, '--r': p.rot + 'deg', animation: 'coinRain ' + p.dur + 's linear ' + p.delay + 's 1' }}>{p.e}</span>
        ))}
        {burst && burst.map((p, i) => (
          <span key={'b' + i} style={{ position: 'fixed', left: '50%', top: '50%', fontSize: p.size, '--bx': p.bx + 'px', '--by': p.by + 'px', '--br': p.rot + 'deg', animation: 'coinBurst ' + p.dur + 's ease-out forwards' }}>{p.e}</span>
        ))}
        {orbit && (
          <div style={{ position: 'fixed', left: '50%', top: '50%', width: 0, height: 0, animation: 'coinSpinRing 2s linear infinite' }}>
            {['⭐', '✨', '💫', '🌟', '💰', '🪙'].map((e, i, arr) => {
              const a = (i / arr.length) * 2 * Math.PI, R = 116;
              return <span key={i} style={{ position: 'absolute', left: Math.cos(a) * R, top: Math.sin(a) * R, fontSize: 26, transform: 'translate(-50%,-50%)' }}>{e}</span>;
            })}
          </div>
        )}
        {fly && (
          <>
            <img src={LOGO} alt="" draggable={false} onClick={onCoinClick}
              style={{ position: 'fixed', left: fly.x, top: fly.y, width: 40, transformStyle: 'preserve-3d',
                transform: `translate(-50%,-50%) scale(${fly.s}) rotate(${fly.rz}deg) rotateY(${fly.ry}deg)`,
                transition: `all ${fly.dur}s ${fly.ease}`, filter: 'drop-shadow(0 8px 18px rgba(0,0,0,0.35))',
                pointerEvents: chase > 0 ? 'auto' : 'none', cursor: chase > 0 ? 'pointer' : 'default', willChange: 'transform', userSelect: 'none' }} />
            {(chase > 0 || bubble) && (
              <div style={{ position: 'fixed', left: fly.x, top: fly.y - 56, transform: 'translate(-50%,-100%)',
                transition: `all ${fly.dur}s ${fly.ease}`, background: '#fff', borderRadius: 12, padding: '3px 9px',
                fontSize: chase > 0 ? 12 : 20, fontWeight: 700, color: ACCENT, boxShadow: '0 4px 14px rgba(0,0,0,0.2)', whiteSpace: 'nowrap' }}>
                {chase > 0 ? 'catch me! 😜' : bubble}
              </div>
            )}
          </>
        )}
      </div>
    )}
    </>
  );
}

/* ----------------------------- HOME / quick add ----------------------------- */

function HomeTab({ data, cats, rates, activeTrip, catById, onAdd, onAddRecurring, onAddCategory, onEdit }) {
  const baseCur = activeTrip ? activeTrip.currency : BASE_CUR;
  const [raw, setRaw] = useState('');
  const [amount, setAmount] = useState('');
  const [currency, setCurrency] = useState(baseCur);
  const [catId, setCatId] = useState(null);
  const [subId, setSubId] = useState(null);
  const [date, setDate] = useState(todayISO());
  const [special, setSpecial] = useState(false);
  const [useCustomDate, setUseCustomDate] = useState(false);
  const [useSpread, setUseSpread] = useState(false);
  const [useRepeat, setUseRepeat] = useState(false);
  const [repeatFreq, setRepeatFreq] = useState('monthly');
  const [repeatEnd, setRepeatEnd] = useState('');
  const [spreadStart, setSpreadStart] = useState(todayISO());
  const [spreadEnd, setSpreadEnd] = useState(todayISO());
  const [flash, setFlash] = useState(false);
  const [addingCat, setAddingCat] = useState(false);
  const [newCatName, setNewCatName] = useState('');
  const [newCatColor, setNewCatColor] = useState('#10B981');
  const inputRef = useRef(null);

  useEffect(() => { setCurrency(baseCur); }, [baseCur]);

  const parsed = parseEntry(raw);
  const desc = parsed.desc;
  const effAmount = amount !== '' ? parseFloat(amount) : parsed.amount;

  // live suggestion
  useEffect(() => {
    if (!desc) return;
    const s = suggestCategory(desc);
    if (s && !catId) { setCatId(s.catId); setSubId(s.subId); }
  }, [desc]); // eslint-disable-line

  const selectedCat = catId ? catById[catId] : null;
  const sortedCats = useMemo(() => {
    if (!activeTrip) return cats;
    return [...cats].sort((a, b) => (b.travel ? 1 : 0) - (a.travel ? 1 : 0));
  }, [cats, activeTrip]);

  const canAdd = effAmount > 0 && catId;

  // spread range -> number of days (end clamped to >= start)
  const spreadDayCount = (special && useSpread)
    ? Math.max(1, daysBetween(spreadStart, spreadEnd < spreadStart ? spreadStart : spreadEnd) + 1)
    : 1;
  const setPresetDays = (n) => {
    const d = new Date(spreadStart + 'T00:00:00');
    d.setDate(d.getDate() + (n - 1));
    setSpreadEnd(isoDate(d));
  };

  const reset = () => {
    setRaw(''); setAmount(''); setCatId(null); setSubId(null);
    setDate(todayISO()); setCurrency(baseCur);
    setSpecial(false); setUseCustomDate(false); setUseSpread(false);
    setUseRepeat(false); setRepeatFreq('monthly'); setRepeatEnd('');
    setSpreadStart(todayISO()); setSpreadEnd(todayISO());
    inputRef.current?.focus();
  };

  const submit = (cid = catId, sid = subId) => {
    if (!(effAmount > 0 && cid)) return;
    if (special && useRepeat) {
      onAddRecurring({
        id: uid(),
        desc: desc || catById[cid].name,
        original: effAmount, currency,
        catId: cid, subId: sid,
        freq: repeatFreq, startDate: date, lastPosted: null,
        endDate: repeatEnd || null,
        tripId: activeTrip ? activeTrip.id : null,
        active: true, created: Date.now(),
      });
    } else {
      onAdd({
        id: uid(),
        desc: desc || catById[cid].name,
        original: effAmount,
        currency,
        sgd: toBase(effAmount, currency, rates),
        catId: cid, subId: sid,
        date,
        spreadDays: spreadDayCount,
        spreadStart: (special && useSpread) ? spreadStart : null,
        tripId: activeTrip ? activeTrip.id : null,
        ts: Date.now(),
      });
    }
    setFlash(special && useRepeat ? 'Recurring set up' : 'Added');
    setTimeout(() => setFlash(false), 1400);
    reset();
  };

  // today's spend
  const todays = data.expenses.filter((e) => e.date === todayISO());
  const todayTotal = todays.reduce((s, e) => s + e.sgd, 0);
  const recent = data.expenses.slice(0, 6);
  const accent = activeTrip?.color || ACCENT;

  return (
    <div className="space-y-4">
      {activeTrip && (
        <div className="flex items-center gap-2 text-sm px-3 py-3 rounded-2xl text-white"
          style={{ background: `linear-gradient(135deg, ${accent}, ${accent}cc)` }}>
          <span className="text-lg leading-none">{activeTrip.emoji || '✈️'}</span>
          <span className="font-semibold">Logging to {activeTrip.name}</span>
          <span className="opacity-80 ml-auto text-xs">tap Trips to switch off</span>
        </div>
      )}

      {/* smart input */}
      <Card className="p-4">
        <div className="flex items-center justify-between">
          <label className="text-xs text-gray-400 font-medium">What did you spend on?</label>
          <button onClick={() => setSpecial((v) => !v)}
            className="px-3 py-1 rounded-full text-xs font-semibold border transition active:scale-95"
            style={special
              ? { background: accent, borderColor: accent, color: '#fff' }
              : { background: '#fff', borderColor: '#E5E7EB', color: '#6B7280' }}>
            Special Expense
          </button>
        </div>
        <input
          ref={inputRef}
          autoFocus
          value={raw}
          onChange={(e) => setRaw(e.target.value)}
          onKeyDown={(e) => { if (e.key === 'Enter') submit(); }}
          placeholder="e.g. grab 15.50  or  lunch 12"
          className="w-full mt-1 text-lg outline-none placeholder-gray-300 bg-transparent"
        />
        <div className="flex items-center gap-2 mt-3">
          <div className="flex items-center gap-1 px-3 py-2 rounded-xl bg-gray-50 flex-1">
            <span className="text-gray-400 text-sm">{SYMBOLS[currency] || currency}</span>
            <input
              inputMode="decimal"
              value={amount}
              onChange={(e) => setAmount(e.target.value.replace(/[^\d.]/g, ''))}
              onKeyDown={(e) => { if (e.key === 'Enter') submit(); }}
              placeholder={parsed.amount != null ? String(parsed.amount) : '0.00'}
              className="w-full bg-transparent outline-none text-lg tnum"
            />
          </div>
          {activeTrip && (
            <select value={currency} onChange={(e) => setCurrency(e.target.value)}
              className="px-3 py-2 rounded-xl bg-gray-50 text-sm font-medium outline-none">
              {Object.keys(rates).map((c) => <option key={c} value={c}>{c}</option>)}
            </select>
          )}
        </div>
        {currency !== 'SGD' && effAmount > 0 && (
          <div className="text-xs text-gray-400 mt-1.5 tnum">
            ≈ {fmtSGD(toBase(effAmount, currency, rates))}
          </div>
        )}

        {special && (
          <div className="mt-3 rounded-xl p-3 space-y-3" style={{ background: accent + '12' }}>
            <div className="text-xs text-gray-500">For anything that isn't a normal "right now" entry. Tap what you need:</div>

            <div className="flex gap-2">
              <button onClick={() => setUseCustomDate((v) => !v)}
                className="flex-1 flex items-center justify-center gap-1.5 px-2 py-2 rounded-xl text-sm font-medium border transition active:scale-[0.98]"
                style={useCustomDate
                  ? { background: accent, borderColor: accent, color: '#fff' }
                  : { background: '#fff', borderColor: '#E5E7EB', color: '#6B7280' }}>
                <Calendar size={14} /> Date
              </button>
              <button onClick={() => { setUseSpread((v) => !v); if (!useSpread) setUseRepeat(false); }}
                className="flex-1 flex items-center justify-center gap-1.5 px-2 py-2 rounded-xl text-sm font-medium border transition active:scale-[0.98]"
                style={useSpread
                  ? { background: accent, borderColor: accent, color: '#fff' }
                  : { background: '#fff', borderColor: '#E5E7EB', color: '#6B7280' }}>
                <Layers size={14} /> Spread
              </button>
              <button onClick={() => { setUseRepeat((v) => !v); if (!useRepeat) setUseSpread(false); }}
                className="flex-1 flex items-center justify-center gap-1.5 px-2 py-2 rounded-xl text-sm font-medium border transition active:scale-[0.98]"
                style={useRepeat
                  ? { background: accent, borderColor: accent, color: '#fff' }
                  : { background: '#fff', borderColor: '#E5E7EB', color: '#6B7280' }}>
                <RotateCcw size={14} /> Repeat
              </button>
            </div>

            {useCustomDate && (
              <div className="flex items-center justify-between gap-2 pt-1">
                <span className="text-sm text-gray-600 font-medium">Log {useRepeat ? 'first one' : 'this'} on</span>
                <input type="date" value={date}
                  onChange={(e) => setDate(e.target.value)}
                  className="px-2.5 py-1.5 rounded-lg bg-white border border-gray-200 outline-none text-sm" />
              </div>
            )}
            {useCustomDate && date > todayISO() && !useRepeat && (
              <div className="text-xs" style={{ color: ACCENT }}>Future date — it'll appear under Upcoming in History until then.</div>
            )}

            {useRepeat && (
              <div className="pt-1">
                <div className="text-sm text-gray-600 font-medium mb-1.5">Repeat this expense</div>
                <div className="flex gap-1.5">
                  {[['Every week', 'weekly'], ['Every month', 'monthly']].map(([lab, f]) => (
                    <button key={f} onClick={() => setRepeatFreq(f)}
                      className="flex-1 px-2.5 py-1.5 rounded-lg text-xs font-medium border"
                      style={repeatFreq === f
                        ? { background: accent, borderColor: accent, color: '#fff' }
                        : { background: '#fff', borderColor: '#E5E7EB', color: '#6B7280' }}>
                      {lab}
                    </button>
                  ))}
                </div>
                <div className="flex items-center justify-between gap-2 mt-2">
                  <span className="text-sm text-gray-600">Stops on <span className="text-gray-400">(optional)</span></span>
                  <div className="flex items-center gap-1.5">
                    <input type="date" value={repeatEnd} min={date}
                      onChange={(e) => setRepeatEnd(e.target.value)}
                      className="px-2.5 py-1.5 rounded-lg bg-white border border-gray-200 outline-none text-sm" />
                    {repeatEnd && <button onClick={() => setRepeatEnd('')} className="text-gray-400"><X size={15} /></button>}
                  </div>
                </div>
                <div className="text-xs text-gray-500 mt-2">
                  Starts {date === todayISO() ? 'today' : prettyDate(date)}{repeatEnd ? `, until ${prettyDate(repeatEnd)}` : ''} and logs itself automatically. Manage or stop it in Settings.
                </div>
              </div>
            )}

            {useSpread && (
              <div className="pt-1">
                <div className="text-sm text-gray-600 font-medium mb-1.5">Spread the cost across these days</div>
                <div className="flex items-center gap-2">
                  <input type="date" value={spreadStart}
                    onChange={(e) => { setSpreadStart(e.target.value); if (spreadEnd < e.target.value) setSpreadEnd(e.target.value); }}
                    className="flex-1 min-w-0 px-2 py-1.5 rounded-lg bg-white border border-gray-200 outline-none text-sm" />
                  <span className="text-gray-400 text-sm shrink-0">to</span>
                  <input type="date" value={spreadEnd} min={spreadStart}
                    onChange={(e) => setSpreadEnd(e.target.value)}
                    className="flex-1 min-w-0 px-2 py-1.5 rounded-lg bg-white border border-gray-200 outline-none text-sm" />
                </div>
                <div className="flex flex-wrap gap-1.5 mt-2">
                  {[['Just this day', 1], ['Weekend', 2], ['Week', 7], ['Month', 30], ['Year', 365]].map(([lab, n]) => (
                    <button key={lab} onClick={() => setPresetDays(n)}
                      className="px-2.5 py-1 rounded-lg text-xs font-medium border"
                      style={spreadDayCount === n
                        ? { background: accent, borderColor: accent, color: '#fff' }
                        : { background: '#fff', borderColor: '#E5E7EB', color: '#6B7280' }}>
                      {lab}
                    </button>
                  ))}
                </div>
                <div className="text-xs text-gray-500 mt-2 tnum">
                  {spreadDayCount} day{spreadDayCount === 1 ? '' : 's'}
                  {effAmount > 0 && <> · ≈ {fmtSGD(toBase(effAmount, currency, rates) / spreadDayCount)}/day</>}
                </div>
              </div>
            )}
          </div>
        )}
      </Card>

      {/* category chips — tap to log instantly */}
      <div>
        <div className="flex items-center justify-between mb-2 px-1">
          <span className="text-xs text-gray-400 font-medium">Category{effAmount > 0 ? ' · tap to log' : ''}</span>
          {flash && (
            <span className="flex items-center gap-1 text-xs font-semibold" style={{ color: ACCENT }}>
              <Check size={13} /> {flash}
            </span>
          )}
        </div>
        <div className="flex flex-wrap gap-2">
          {sortedCats.map((c) => {
            const on = catId === c.id;
            const hasSubs = c.subs && c.subs.length > 0;
            return (
              <button key={c.id}
                onClick={() => {
                  if (effAmount > 0 && !hasSubs) { submit(c.id, null); }
                  else { setCatId(c.id); setSubId(null); if (effAmount <= 0) inputRef.current?.focus(); }
                }}
                className="flex items-center gap-1.5 px-3 py-2 rounded-xl text-sm font-medium border transition active:scale-95"
                style={on
                  ? { background: c.color, borderColor: c.color, color: '#fff' }
                  : { background: '#fff', borderColor: '#F0F0F0', color: '#4B5563' }}>
                <Dot color={on ? '#ffffff' : c.color} />
                {c.name}
              </button>
            );
          })}
          <button onClick={() => setAddingCat((v) => !v)}
            className="flex items-center gap-1.5 px-3 py-2 rounded-xl text-sm font-medium border border-dashed transition active:scale-95"
            style={{ background: '#fff', borderColor: ACCENT + '70', color: ACCENT }}>
            <Plus size={14} /> Add category
          </button>
        </div>
        {effAmount > 0 && (
          <div className="text-xs text-gray-400 mt-2 px-1">Tap a category to log {fmtSGD(toBase(effAmount, currency, rates))} now.</div>
        )}
      </div>

      {/* inline add-category form */}
      {addingCat && (
        <Card className="p-3 space-y-3">
          <input value={newCatName} onChange={(e) => setNewCatName(e.target.value)}
            placeholder="Category name (e.g. Pets, Gifts)" autoFocus
            className="w-full px-3 py-2 rounded-xl bg-gray-50 border border-gray-200 outline-none text-sm" />
          <div>
            <div className="text-xs text-gray-400 font-medium mb-1.5">Colour</div>
            <div className="flex flex-wrap gap-2">
              {['#10B981', '#F59E0B', '#3B82F6', '#8B5CF6', '#EC4899', '#EF4444', '#14B8A6', '#6366F1', '#0EA5E9', '#64748B'].map((col) => (
                <button key={col} onClick={() => setNewCatColor(col)}
                  className="w-7 h-7 rounded-full"
                  style={{ background: col, outline: newCatColor === col ? '2px solid var(--ink)' : 'none', outlineOffset: 2 }} />
              ))}
            </div>
          </div>
          <div className="flex gap-2">
            <button onClick={() => { setAddingCat(false); setNewCatName(''); }}
              className="flex-1 py-2 rounded-xl text-sm font-medium border border-gray-200 text-gray-500">Cancel</button>
            <button disabled={!newCatName.trim()}
              onClick={() => {
                const c = { id: uid(), name: newCatName.trim(), color: newCatColor, subs: [] };
                onAddCategory(c); setCatId(c.id); setSubId(null);
                setAddingCat(false); setNewCatName('');
              }}
              className="flex-1 py-2 rounded-xl text-sm font-semibold text-white"
              style={{ background: newCatName.trim() ? ACCENT : '#C9CFCB' }}>Add category</button>
          </div>
        </Card>
      )}

      {/* subcategory chips */}
      {selectedCat && selectedCat.subs.length > 0 && (
        <div>
          <div className="text-xs text-gray-400 font-medium mb-2 px-1">{selectedCat.name} type{effAmount > 0 ? ' · tap to log' : ''}</div>
          <div className="flex flex-wrap gap-2">
            {selectedCat.subs.map((s) => {
              const on = subId === s.id;
              return (
                <button key={s.id}
                  onClick={() => { if (effAmount > 0) submit(selectedCat.id, s.id); else setSubId(on ? null : s.id); }}
                  className="px-3 py-1.5 rounded-lg text-sm border transition active:scale-95"
                  style={on
                    ? { background: '#1B2420', borderColor: '#1B2420', color: '#fff' }
                    : { background: '#fff', borderColor: '#F0F0F0', color: '#6B7280' }}>
                  {s.name}
                </button>
              );
            })}
          </div>
          {effAmount > 0 && (
            <button onClick={() => submit(selectedCat.id, null)}
              className="text-xs underline mt-2 px-1" style={{ color: ACCENT }}>
              Log without a type
            </button>
          )}
        </div>
      )}

      {/* today summary */}
      <Card className="p-4 flex items-center justify-between">
        <div>
          <div className="text-xs text-gray-400 font-medium">Spent today</div>
          <div className="text-xl font-semibold tnum mt-0.5">{fmtSGD(todayTotal)}</div>
        </div>
        <div className="text-xs text-gray-400">{todays.length} item{todays.length === 1 ? '' : 's'}</div>
      </Card>

      {/* mascot above, daily quote underneath, on the green background above Recent */}
      <div className="flex flex-col items-center gap-2 pt-1">
        <img src={M_BAG} alt="" className="mascot w-36 h-36" style={{ objectFit: 'contain' }} />
        <QuoteCard />
      </div>

      {/* recent */}
      {recent.length > 0 ? (
        <div>
          <div className="text-xs text-gray-400 font-medium mb-2 px-1">Recent</div>
          <Card className="divide-y divide-gray-50">
            {recent.map((e) => (
              <ExpenseRow key={e.id} e={e} cat={catById[e.catId]} onClick={() => onEdit(e)} />
            ))}
          </Card>
        </div>
      ) : (
        <div className="text-center text-gray-400 text-sm py-2">
          Nothing logged yet. Type something above and tap a category to start.
        </div>
      )}
    </div>
  );
}

function ExpenseRow({ e, cat, onClick, amount, note, lead, selected }) {
  const sub = cat?.subs.find((s) => s.id === e.subId);
  const shown = amount != null ? amount : e.sgd;
  const split = (e.spreadDays || 1) > 1;
  return (
    <button onClick={onClick} className="w-full flex items-center gap-3 px-4 py-3 text-left active:bg-gray-50"
      style={selected ? { background: ACCENT + '12' } : undefined}>
      {lead}
      <Dot color={cat?.color || '#94A3B8'} />
      <div className="flex-1 min-w-0">
        <div className="text-sm font-medium truncate">
          {e.desc}
          {split && <span className="ml-1.5 text-xs font-medium px-1.5 py-0.5 rounded" style={{ color: ACCENT, background: ACCENT + '14' }}>split · {e.spreadDays}d</span>}
        </div>
        <div className="text-xs text-gray-400 truncate">
          {cat?.name || 'Uncategorized'}{sub ? ' · ' + sub.name : ''} · {prettyDate(e.date)}{note ? ' · ' + note : ''}
        </div>
      </div>
      <div className="text-right">
        <div className="text-sm font-semibold tnum">{fmtSGD(shown)}</div>
        {amount == null && e.currency !== 'SGD' && (
          <div className="text-xs text-gray-400 tnum">{fmtNum(e.original, e.currency)}</div>
        )}
        {amount != null && split && (
          <div className="text-xs text-gray-400 tnum">of {fmtSGD(e.sgd)}</div>
        )}
      </div>
    </button>
  );
}

/* ----------------------------- INSIGHTS ----------------------------- */

function InsightsTab({ data, cats, catById, activeTrip, onEdit }) {
  const [mode, setMode] = useState('month'); // 'week' | 'month' | 'year' | 'trips'
  const [anchor, setAnchor] = useState(todayISO());
  const [detailCatId, setDetailCatId] = useState(null);
  const [dayDetail, setDayDetail] = useState(null);
  const [pickerOpen, setPickerOpen] = useState(false);
  const [listSort, setListSort] = useState(data.defaultSort || 'amount_desc');

  if (mode === 'trips') {
    return (
      <div className="space-y-4">
        <Segmented value="trips" onChange={(v) => { setAnchor(todayISO()); setMode(v); }}
          options={[{ v: 'day', label: 'Day' }, { v: 'week', label: 'Week' }, { v: 'month', label: 'Month' }, { v: 'year', label: 'Year' }, { v: 'trips', label: 'Trips' }]} />
        <TripInsights data={data} cats={cats} catById={catById} />
      </div>
    );
  }

  const type = mode; // day | week | month | year
  const [start, end] = periodRange(type, anchor);
  const inRange = (e) => e.date >= start && e.date <= end;          // transaction-based
  const inRangeDate = (ds) => ds >= start && ds <= end;            // allocation-based
  const periodExp = data.expenses.filter(inRange);

  if (detailCatId && catById[detailCatId]) {
    return (
      <CategoryDetail
        cat={catById[detailCatId]} data={data} catById={catById}
        initialType={type} initialAnchor={anchor}
        onBack={() => setDetailCatId(null)} onEdit={onEdit}
      />
    );
  }
  if (dayDetail) {
    return (
      <DayDetail date={dayDetail} data={data} cats={cats} catById={catById}
        onBack={() => setDayDetail(null)} onEdit={onEdit} />
    );
  }

  // spread-aware totals (split expenses contribute a daily share)
  const periodAllocs = allocInRange(data.expenses, inRangeDate);
  const total = periodAllocs.reduce((s, a) => s + a.amt, 0);
  const today = todayISO();
  const isCurrent = today >= start && today <= end;
  const periodDays = daysBetween(start, end) + 1;
  const elapsed = isCurrent ? daysBetween(start, today) + 1 : periodDays;
  const dailyAvg = elapsed ? total / elapsed : 0;
  const projected = dailyAvg * periodDays;

  const prevAnchor = shiftAnchor(type, anchor, -1);
  const [ps, pe] = periodRange(type, prevAnchor);
  const prevTotal = allocInRange(data.expenses, (ds) => ds >= ps && ds <= pe).reduce((s, a) => s + a.amt, 0);
  const delta = prevTotal ? ((total - prevTotal) / prevTotal) * 100 : null;

  const byCat = groupAllocByCat(periodAllocs, cats);
  const budgets = data.budgets || { week: 0, month: data.budget || 0, year: 0 };
  const budget = budgets[type] || (type === 'month' ? (data.budget || 0) : 0);
  const budgetLabel = type === 'week' ? 'Weekly budget' : type === 'year' ? 'Yearly budget' : 'Monthly budget';

  // transaction-based lists (actual purchases, by purchase date)
  const txnTotal = periodExp.reduce((s, e) => s + e.sgd, 0);
  const avgTxn = periodExp.length ? txnTotal / periodExp.length : 0;
  const sortedBySize = [...periodExp].sort((a, b) => b.sgd - a.sgd);
  const biggestExp = sortedBySize[0] || null;
  const leastExp = sortedBySize[sortedBySize.length - 1] || null;
  const topExp = sortedBySize.slice(0, 5);

  // trend buckets (spread-aware): months for year, days for week/month, none for day
  const buckets = buildBuckets(type, start, end, periodAllocs, isCurrent, today);
  const bucketMax = buckets.reduce((m, b) => (b.amt > m ? b.amt : m), 0);
  let mostB = null, leastB = null;
  for (const b of buckets) if (b.amt > 0) {
    if (!mostB || b.amt > mostB.amt) mostB = b;
    if (!leastB || b.amt < leastB.amt) leastB = b;
  }
  const pickBucket = (b) => {
    if (!b) return;
    if (b.kind === 'day') setDayDetail(b.key);
    else { setMode('month'); setAnchor(b.key + '-01'); } // jump into that month
  };

  const canNext = end < today;
  const unit = type === 'year' ? 'month' : 'day';
  const showProjected = isCurrent && type !== 'day';

  return (
    <div className="space-y-4">
      <Segmented value={type} onChange={(v) => { setAnchor(todayISO()); setMode(v); }}
        options={[{ v: 'day', label: 'Day' }, { v: 'week', label: 'Week' }, { v: 'month', label: 'Month' }, { v: 'year', label: 'Year' }, { v: 'trips', label: 'Trips' }]} />

      {/* period navigator */}
      <div className="flex items-center justify-between">
        <button onClick={() => setAnchor(shiftAnchor(type, anchor, -1))}
          className="p-2 rounded-lg bg-white border border-gray-100 text-gray-500 active:scale-95"><ChevronLeft size={18} /></button>
        <button onClick={() => setPickerOpen(true)}
          className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-white border border-gray-100 text-sm font-semibold">
          <Calendar size={15} className="text-gray-400" />
          {periodLabelLong(type, anchor)}
          {isCurrent && <span className="text-xs font-medium" style={{ color: ACCENT }}>· now</span>}
        </button>
        <button onClick={() => canNext && setAnchor(shiftAnchor(type, anchor, 1))} disabled={!canNext}
          className="p-2 rounded-lg bg-white border border-gray-100 active:scale-95"
          style={{ color: canNext ? '#6B7280' : '#D1D5DB' }}><ChevronRight size={18} /></button>
      </div>

      <div className="flex gap-3">
        <StatTile label="Total" value={fmtSGD(total)} tone={ACCENT} />
        <StatTile label="Daily avg" value={fmtSGD(dailyAvg)} sub={`over ${elapsed} day${elapsed === 1 ? '' : 's'}`} />
      </div>
      <div className="flex gap-3">
        <StatTile label={showProjected ? `Projected ${type}` : 'Transactions'}
          value={showProjected ? fmtSGD(projected) : String(periodExp.length)} />
        <Card className="p-4 flex-1">
          <div className="text-xs text-gray-400 font-medium">vs last {type}</div>
          {delta == null ? (
            <div className="text-xl font-semibold mt-1 text-gray-300">—</div>
          ) : (
            <div className="text-xl font-semibold mt-1 flex items-center gap-1 tnum"
              style={{ color: delta > 0 ? '#DC2626' : ACCENT }}>
              {delta > 0 ? <TrendingUp size={18} /> : <TrendingDown size={18} />}
              {Math.abs(delta).toFixed(0)}%
            </div>
          )}
        </Card>
      </div>

      {budget > 0 && (type === 'week' || type === 'month' || type === 'year') && isCurrent && (
        <Card className="p-4">
          <div className="flex items-center justify-between text-sm">
            <span className="text-gray-500 font-medium">{budgetLabel}</span>
            <span className="tnum text-gray-500">{fmtSGD(total)} / {fmtSGD(budget)}</span>
          </div>
          <div className="h-2.5 rounded-full bg-gray-100 mt-2 overflow-hidden">
            <div className="h-full rounded-full" style={{
              width: Math.min(100, (total / budget) * 100) + '%',
              background: total > budget ? '#DC2626' : ACCENT,
            }} />
          </div>
          <div className="text-xs mt-1.5" style={{ color: total > budget ? '#DC2626' : '#6B7280' }}>
            {total > budget ? `Over by ${fmtSGD(total - budget)}` : `${fmtSGD(budget - total)} left`}
          </div>
        </Card>
      )}

      {total === 0 ? (
        <div className="text-center text-gray-400 text-sm py-10">
          No spending recorded for this {type} yet.
        </div>
      ) : (
        <>
          <Card className="p-4">
            <div className="text-xs text-gray-400 font-medium mb-1">Where it went</div>
            <DonutChart data={byCat} total={total} caption="Total"
              onSlice={(id) => setDetailCatId(id)} />
            <div className="text-center text-xs text-gray-400 mt-1">Tap a slice to see its amount · tap a category below for every expense</div>
          </Card>

          <Card className="divide-y divide-gray-50">
            {byCat.map((c) => (
              <button key={c.id} onClick={() => setDetailCatId(c.id)}
                className="w-full px-4 py-3 text-left active:bg-gray-50">
                <div className="flex items-center justify-between text-sm">
                  <div className="flex items-center gap-2 min-w-0">
                    <Dot color={c.color} /><span className="font-medium truncate">{c.name}</span>
                  </div>
                  <div className="flex items-center gap-2 shrink-0 tnum">
                    <span className="font-semibold">{fmtSGD(c.value)}</span>
                    <span className="text-gray-400">{Math.round((c.value / total) * 100)}%</span>
                    <ChevronRight size={15} className="text-gray-300" />
                  </div>
                </div>
                <div className="h-1.5 rounded-full bg-gray-100 mt-2 overflow-hidden">
                  <div className="h-full rounded-full" style={{ width: (c.value / total) * 100 + '%', background: c.color }} />
                </div>
              </button>
            ))}
          </Card>

          {type !== 'day' && (
            <Card className="p-4">
              <div className="text-xs text-gray-400 font-medium mb-3">
                {type === 'year' ? 'Monthly spending · tap a month' : 'Daily spending · tap any day'}
              </div>
              <BucketBars buckets={buckets} max={bucketMax} color={ACCENT} onPick={pickBucket} />
            </Card>
          )}

          <StatTile label="Average per expense" value={fmtSGD(avgTxn)} />

          {type !== 'day' && (
            <div className="flex gap-3">
              <BucketStatCard label={`Most spent (${unit})`} bucket={mostB} onClick={() => pickBucket(mostB)} />
              <BucketStatCard label={`Least spent (${unit})`} bucket={leastB} onClick={() => pickBucket(leastB)} />
            </div>
          )}

          <div>
            <div className="flex items-center justify-between mb-2 px-1">
              <span className="text-xs text-gray-400 font-medium">Expenses this {type}</span>
              <SortSelect value={listSort} onChange={setListSort} />
            </div>
            <Card className="divide-y divide-gray-50">
              {[...periodExp].sort(SORTS[listSort].cmp).slice(0, 50).map((e) => (
                <ExpenseRow key={e.id} e={e} cat={catById[e.catId]} onClick={() => onEdit && onEdit(e)} />
              ))}
            </Card>
            {periodExp.length > 50 && (
              <div className="text-xs text-gray-400 text-center mt-1">Showing 50 of {periodExp.length} — open History to see all</div>
            )}
          </div>
        </>
      )}

      {pickerOpen && (
        <PeriodPicker type={type} anchor={anchor}
          onClose={() => setPickerOpen(false)}
          onPick={(a) => { setAnchor(a); setPickerOpen(false); }} />
      )}

      {/* a little something at the very bottom */}
      <div className="flex flex-col items-center gap-1.5 pt-4 pb-1">
        <div className="font-medium" style={{ fontSize: 11, letterSpacing: '0.03em', color: '#5B6960' }}>a word from the finance department</div>
        <img src={MEMES[({ day: 0, week: 1, month: 2, year: 3 }[type]) ?? 0]} alt="" className="rounded-2xl" style={{ maxWidth: 230, width: '100%', boxShadow: '0 2px 12px rgba(0,0,0,0.07)' }} />
      </div>
    </div>
  );
}

function PeriodPicker({ type, anchor, onClose, onPick }) {
  const init = new Date(anchor + 'T00:00:00');
  const [viewY, setViewY] = useState(init.getFullYear());
  const [viewM, setViewM] = useState(init.getMonth());
  const todayY = new Date().getFullYear();
  const swatch = (sel) => sel
    ? { background: ACCENT, color: '#fff', borderColor: ACCENT }
    : { background: '#fff', borderColor: '#E5E7EB', color: '#374151' };

  let body;
  if (type === 'year') {
    const years = [];
    for (let y = todayY + 1; y >= todayY - 10; y--) years.push(y);
    body = (
      <div className="grid grid-cols-3 gap-2">
        {years.map((y) => (
          <button key={y} onClick={() => onPick(`${y}-06-15`)}
            className="py-3 rounded-xl text-sm font-medium border" style={swatch(y === init.getFullYear())}>
            {y}
          </button>
        ))}
      </div>
    );
  } else if (type === 'month') {
    const mns = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
    body = (
      <>
        <div className="flex items-center justify-center gap-4">
          <button onClick={() => setViewY(viewY - 1)} className="p-2 text-gray-500"><ChevronLeft size={18} /></button>
          <span className="font-semibold text-base w-16 text-center">{viewY}</span>
          <button onClick={() => setViewY(viewY + 1)} className="p-2 text-gray-500"><ChevronRight size={18} /></button>
        </div>
        <div className="grid grid-cols-3 gap-2 mt-3">
          {mns.map((mn, i) => (
            <button key={mn} onClick={() => onPick(`${viewY}-${String(i + 1).padStart(2, '0')}-15`)}
              className="py-3 rounded-xl text-sm font-medium border"
              style={swatch(viewY === init.getFullYear() && i === init.getMonth())}>{mn}</button>
          ))}
        </div>
      </>
    );
  } else {
    const first = new Date(viewY, viewM, 1);
    const startDow = (first.getDay() + 6) % 7;
    const dim = new Date(viewY, viewM + 1, 0).getDate();
    const cells = [];
    for (let i = 0; i < startDow; i++) cells.push(null);
    for (let d = 1; d <= dim; d++) cells.push(d);
    const [selS, selE] = periodRange(type, anchor);
    const prevM = () => { if (viewM === 0) { setViewM(11); setViewY(viewY - 1); } else setViewM(viewM - 1); };
    const nextM = () => { if (viewM === 11) { setViewM(0); setViewY(viewY + 1); } else setViewM(viewM + 1); };
    body = (
      <>
        <div className="flex items-center justify-center gap-4">
          <button onClick={prevM} className="p-2 text-gray-500"><ChevronLeft size={18} /></button>
          <span className="font-semibold text-base text-center" style={{ minWidth: 150 }}>
            {first.toLocaleDateString('en-SG', { month: 'long', year: 'numeric' })}
          </span>
          <button onClick={nextM} className="p-2 text-gray-500"><ChevronRight size={18} /></button>
        </div>
        <div className="grid grid-cols-7 gap-1 mt-3 text-center">
          {['Mo', 'Tu', 'We', 'Th', 'Fr', 'Sa', 'Su'].map((w) => (
            <div key={w} className="text-gray-400" style={{ fontSize: 11 }}>{w}</div>
          ))}
          {cells.map((d, idx) => {
            if (!d) return <div key={idx} />;
            const ds = `${viewY}-${String(viewM + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
            const inSel = ds >= selS && ds <= selE;
            return (
              <button key={idx} onClick={() => onPick(ds)} className="py-2 rounded-lg text-sm"
                style={inSel ? { background: ACCENT, color: '#fff' } : { color: '#374151' }}>{d}</button>
            );
          })}
        </div>
        <div className="text-xs text-gray-400 text-center mt-2">
          {type === 'day' ? 'Tap any day to view it' : 'Tap any day to view that week'}
        </div>
      </>
    );
  }

  return (
    <div className="fixed inset-0 z-40 flex items-end justify-center" style={{ background: 'rgba(0,0,0,0.35)' }} onClick={onClose}>
      <div className="bg-white w-full max-w-md rounded-t-3xl p-5 space-y-2" onClick={(e) => e.stopPropagation()}>
        <div className="flex items-center justify-between mb-1">
          <h3 className="font-semibold text-lg">Jump to a {type}</h3>
          <button onClick={onClose} className="p-1 text-gray-400"><X size={20} /></button>
        </div>
        {body}
        <button onClick={() => onPick(todayISO())}
          className="w-full py-2.5 mt-2 rounded-xl text-sm font-medium" style={{ background: '#F3F4F6', color: '#374151' }}>
          Jump to today
        </button>
      </div>
    </div>
  );
}


function BucketBars({ buckets, max, color, onPick }) {
  const H = 110;
  return (
    <div className="overflow-x-auto noscroll" style={{ paddingBottom: 2 }}>
      <div className="flex items-end gap-1" style={{ minWidth: buckets.length * 28 }}>
        {buckets.map((b) => {
          const h = b.amt > 0 && max > 0 ? Math.max(5, (b.amt / max) * H) : 2;
          return (
            <button key={b.key} onClick={() => onPick(b)}
              title={`${b.human} · ${fmtSGD(b.amt)}`}
              className="flex flex-col items-center gap-1.5 shrink-0 active:opacity-70"
              style={{ width: 26 }}>
              <div className="w-full flex items-end justify-center" style={{ height: H }}>
                <div className="rounded-t-md transition" style={{
                  width: '70%', height: h,
                  background: b.amt > 0 ? color : '#E5E7EB',
                }} />
              </div>
              <span className="text-gray-400" style={{ fontSize: 10 }}>{b.label}</span>
            </button>
          );
        })}
      </div>
    </div>
  );
}

