/* on-slice percentage labels for the donut */
const RAD = Math.PI / 180;
function pctLabel({ cx, cy, midAngle, innerRadius, outerRadius, percent }) {
  if (percent < 0.07) return null;
  const r = innerRadius + (outerRadius - innerRadius) * 0.5;
  const x = cx + r * Math.cos(-midAngle * RAD);
  const y = cy + r * Math.sin(-midAngle * RAD);
  return (
    <text x={x} y={y} fill="#ffffff" fontSize="11" fontWeight="700"
      textAnchor="middle" dominantBaseline="central">
      {Math.round(percent * 100)}%
    </text>
  );
}

function DonutChart({ data, total, caption, onSlice }) {
  const wrapRef = useRef(null);
  const [hover, setHover] = useState(null); // desktop hover
  const [sel, setSel] = useState(null);     // tapped slice (works on mobile)
  const [pos, setPos] = useState({ x: 0, y: 0 });
  const onMove = (e) => {
    const r = wrapRef.current && wrapRef.current.getBoundingClientRect();
    if (r) setPos({ x: e.clientX - r.left, y: e.clientY - r.top });
  };
  const active = hover != null ? data[hover] : null;
  const shown = sel != null ? data[sel] : null;
  const flipX = pos.x > 200;
  const tapSlice = (idx) => {
    if (sel === idx) {
      if (onSlice) onSlice(data[idx].id); // second tap on the same slice opens it
      else setSel(null);
    } else setSel(idx);
  };
  return (
    <div ref={wrapRef} className="relative" style={{ height: 220 }} onMouseMove={onMove} onMouseLeave={() => setHover(null)}>
      <ResponsiveContainer width="100%" height="100%">
        <PieChart>
          <Pie data={data} dataKey="value" nameKey="name" cx="50%" cy="50%"
            innerRadius={64} outerRadius={94} paddingAngle={2} stroke="none"
            label={pctLabel} labelLine={false} isAnimationActive={false}
            onMouseEnter={(_, idx) => setHover(idx)}
            onClick={(_, idx) => tapSlice(idx)}
            style={{ cursor: 'pointer', outline: 'none' }}>
            {data.map((d, i) => (
              <Cell key={d.id} fill={d.color}
                style={{ outline: 'none', opacity: sel == null || sel === i ? 1 : 0.4, transition: 'opacity 0.15s' }} />
            ))}
          </Pie>
        </PieChart>
      </ResponsiveContainer>
      <div className="absolute inset-0 flex flex-col items-center justify-center" style={{ pointerEvents: 'none' }}>
        {shown ? (
          <div onClick={() => setSel(null)} style={{ pointerEvents: 'auto', cursor: 'pointer', textAlign: 'center', padding: '0 10px' }}>
            <div className="flex items-center justify-center gap-1.5">
              <span style={{ width: 8, height: 8, borderRadius: 8, background: shown.color, flexShrink: 0 }} />
              <span className="truncate" style={{ fontSize: 12, color: '#6B7280', maxWidth: 118 }}>{shown.name}</span>
            </div>
            <div className="font-semibold tnum" style={{ fontSize: 19, color: shown.color, marginTop: 1 }}>{fmtSGD(shown.value)}</div>
            <div style={{ fontSize: 10, color: '#9CA3AF', marginTop: 1 }}>
              {Math.round((shown.value / total) * 100)}%{onSlice ? ' · tap again to open' : ''}
            </div>
          </div>
        ) : (
          <>
            <div className="text-gray-400" style={{ fontSize: 11 }}>{caption}</div>
            <div className="font-semibold tnum" style={{ fontSize: 20, color: 'var(--ink)' }}>{fmtSGD(total)}</div>
          </>
        )}
      </div>
      {active && !shown && (
        <div className="pointer-events-none" style={{
          position: 'absolute', left: pos.x, top: pos.y, zIndex: 60,
          transform: `translate(${flipX ? 'calc(-100% - 12px)' : '12px'}, 12px)`,
          background: '#FFFFFF', border: '1px solid #E5E7EB', borderRadius: 10,
          padding: '7px 11px', boxShadow: '0 8px 24px rgba(0,0,0,0.22)', whiteSpace: 'nowrap',
        }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
            <span style={{ width: 9, height: 9, borderRadius: 9, background: active.color, display: 'inline-block', flexShrink: 0 }} />
            <span style={{ fontSize: 12, fontWeight: 600, color: '#374151' }}>{active.name}</span>
          </div>
          <div className="tnum" style={{ fontSize: 14, fontWeight: 700, marginTop: 2, color: '#111827' }}>{fmtSGD(active.value)}</div>
        </div>
      )}
    </div>
  );
}

function CategoryDetail({ cat, data, catById, initialType, initialAnchor, onBack, onEdit }) {
  const [type, setType] = useState(initialType && initialType !== 'trips' ? initialType : (initialType || 'month'));
  const [anchor, setAnchor] = useState(initialAnchor || todayISO());
  const [pickerOpen, setPickerOpen] = useState(false);
  const [sort, setSort] = useState(data.defaultSort || 'amount_desc');

  const catExp = data.expenses.filter((e) => e.catId === cat.id);
  const allTime = catExp.reduce((s, e) => s + e.sgd, 0);

  const head = (
    <>
      <button onClick={onBack} className="flex items-center gap-2 text-sm font-medium text-gray-500 active:text-gray-700">
        <ArrowLeft size={18} /> Back to insights
      </button>
      <div className="flex items-center gap-2">
        <Dot color={cat.color} />
        <h2 className="text-xl font-semibold">{cat.name}</h2>
      </div>
      <Segmented value={type} onChange={(v) => { setAnchor(todayISO()); setType(v); }}
        options={[{ v: 'day', label: 'Day' }, { v: 'week', label: 'Week' }, { v: 'month', label: 'Month' }, { v: 'year', label: 'Year' }, { v: 'trips', label: 'Trips' }]} />
    </>
  );

  // ---- per-trip view ----
  if (type === 'trips') {
    const rows = data.trips
      .map((t) => ({ t, v: catExp.filter((e) => e.tripId === t.id).reduce((s, e) => s + e.sgd, 0) }))
      .filter((r) => r.v > 0)
      .sort((a, b) => b.v - a.v);
    const tripTotal = rows.reduce((s, r) => s + r.v, 0);
    const mx = Math.max(1, ...rows.map((r) => r.v));
    return (
      <div className="space-y-4">
        {head}
        <Card className="p-4 flex items-center justify-between">
          <div>
            <div className="text-xs text-gray-400 font-medium">{cat.name} across all trips</div>
            <div className="text-2xl font-semibold tnum mt-0.5" style={{ color: cat.color }}>{fmtSGD(tripTotal)}</div>
          </div>
          <div className="text-xs text-gray-400">{rows.length} trip{rows.length === 1 ? '' : 's'}</div>
        </Card>
        {rows.length === 0 ? (
          <div className="text-center text-gray-400 text-sm py-10">No {cat.name.toLowerCase()} spending on any trip yet.</div>
        ) : (
          <Card className="p-4 space-y-3">
            {rows.map(({ t, v }) => (
              <div key={t.id}>
                <div className="flex items-center justify-between text-sm">
                  <span className="font-medium flex items-center gap-1.5">{t.emoji || '✈️'} {t.name}</span>
                  <span className="tnum font-semibold">{fmtSGD(v)}</span>
                </div>
                <div className="h-1.5 rounded-full bg-gray-100 mt-1.5 overflow-hidden">
                  <div className="h-full rounded-full" style={{ width: (v / mx * 100) + '%', background: t.color || cat.color }} />
                </div>
              </div>
            ))}
          </Card>
        )}
      </div>
    );
  }

  // ---- day / week / month / year ----
  const [start, end] = periodRange(type, anchor);
  const inRangeDate = (ds) => ds >= start && ds <= end;
  const allocs = allocInRange(catExp, inRangeDate);
  const total = allocs.reduce((s, a) => s + a.amt, 0);
  const today = todayISO();
  const isCurrent = today >= start && today <= end;

  const prevAnchor = shiftAnchor(type, anchor, -1);
  const [ps, pe] = periodRange(type, prevAnchor);
  const prevTotal = allocInRange(catExp, (ds) => ds >= ps && ds <= pe).reduce((s, a) => s + a.amt, 0);
  const delta = prevTotal ? ((total - prevTotal) / prevTotal) * 100 : null;

  const buckets = buildBuckets(type, start, end, allocs, isCurrent, today);
  const bucketMax = buckets.reduce((m, b) => (b.amt > m ? b.amt : m), 0);
  const pickBucket = (b) => {
    if (!b) return;
    if (b.kind === 'day') { setType('day'); setAnchor(b.key); }
    else { setType('month'); setAnchor(b.key + '-01'); }
  };

  const periodExp = catExp.filter((e) => e.date >= start && e.date <= end);
  const listed = [...periodExp].sort(SORTS[sort].cmp);

  // sub-type breakdown for the period
  const subTotals = (cat.subs || [])
    .map((s) => ({ ...s, value: periodExp.filter((e) => e.subId === s.id).reduce((a, e) => a + e.sgd, 0) }))
    .filter((s) => s.value > 0).sort((a, b) => b.value - a.value);
  const txnTotal = periodExp.reduce((s, e) => s + e.sgd, 0);
  const showSubs = (cat.subs || []).length > 0 && subTotals.length > 0;

  const canNext = end < today;

  return (
    <div className="space-y-4">
      {head}

      {/* period navigator */}
      <div className="flex items-center justify-between">
        <button onClick={() => setAnchor(shiftAnchor(type, anchor, -1))}
          className="p-2 rounded-lg bg-white border border-gray-100 text-gray-500 active:scale-95"><ChevronLeft size={18} /></button>
        <button onClick={() => setPickerOpen(true)}
          className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-white border border-gray-100 text-sm font-semibold">
          <Calendar size={15} className="text-gray-400" />
          {periodLabelLong(type, anchor)}
          {isCurrent && <span className="text-xs font-medium" style={{ color: ACCENT }}>· now</span>}
        </button>
        <button onClick={() => canNext && setAnchor(shiftAnchor(type, anchor, 1))} disabled={!canNext}
          className="p-2 rounded-lg bg-white border border-gray-100 active:scale-95"
          style={{ color: canNext ? '#6B7280' : '#D1D5DB' }}><ChevronRight size={18} /></button>
      </div>

      <div className="flex gap-3">
        <StatTile label={`This ${type}`} value={fmtSGD(total)} tone={cat.color} />
        <StatTile label="All time" value={fmtSGD(allTime)} />
      </div>
      <Card className="p-4">
        <div className="text-xs text-gray-400 font-medium">vs last {type}</div>
        {delta == null ? (
          <div className="text-lg font-semibold mt-1 text-gray-300">— no spending last {type}</div>
        ) : (
          <div className="text-lg font-semibold mt-1 flex items-center gap-1 tnum"
            style={{ color: delta > 0 ? '#DC2626' : ACCENT }}>
            {delta > 0 ? <TrendingUp size={17} /> : <TrendingDown size={17} />}
            {Math.abs(delta).toFixed(0)}% {delta > 0 ? 'more' : 'less'} than last {type}
          </div>
        )}
      </Card>

      {type !== 'day' && buckets.length > 0 && total > 0 && (
        <Card className="p-4">
          <div className="text-xs text-gray-400 font-medium mb-3">
            {cat.name} {type === 'year' ? 'by month · tap a month' : 'by day · tap any day'}
          </div>
          <BucketBars buckets={buckets} max={bucketMax} color={cat.color} onPick={pickBucket} />
        </Card>
      )}

      {showSubs && (
        <Card className="p-4 space-y-2.5">
          <div className="text-xs text-gray-400 font-medium">By type</div>
          {subTotals.map((s) => (
            <div key={s.id}>
              <div className="flex items-center justify-between text-sm">
                <span className="font-medium">{s.name}</span>
                <span className="tnum"><span className="font-semibold">{fmtSGD(s.value)}</span>
                  <span className="text-gray-400 ml-2">{txnTotal ? Math.round((s.value / txnTotal) * 100) : 0}%</span></span>
              </div>
              <div className="h-1.5 rounded-full bg-gray-100 mt-1.5 overflow-hidden">
                <div className="h-full rounded-full" style={{ width: (txnTotal ? s.value / txnTotal * 100 : 0) + '%', background: cat.color }} />
              </div>
            </div>
          ))}
        </Card>
      )}

      <div>
        <div className="flex items-center justify-between mb-2 px-1">
          <span className="text-xs text-gray-400 font-medium">Expenses this {type}</span>
          {listed.length > 1 && <SortSelect value={sort} onChange={setSort} />}
        </div>
        {listed.length === 0 ? (
          <div className="text-center text-gray-400 text-sm py-10">
            No {cat.name.toLowerCase()} spending this {type}.
          </div>
        ) : (
          <Card className="divide-y divide-gray-50">
            {listed.map((e) => (
              <ExpenseRow key={e.id} e={e} cat={catById[e.catId]} onClick={() => onEdit && onEdit(e)} />
            ))}
          </Card>
        )}
      </div>

      {pickerOpen && (
        <PeriodPicker type={type} anchor={anchor}
          onClose={() => setPickerOpen(false)}
          onPick={(a) => { setAnchor(a); setPickerOpen(false); }} />
      )}
    </div>
  );
}

function DayDetail({ date, data, cats, catById, onBack, onEdit }) {
  // allocations landing on this date (spread expenses contribute a share)
  const allocs = [];
  for (const e of data.expenses) for (const a of allocations(e)) if (a.date === date) allocs.push(a);
  allocs.sort((x, y) => y.amt - x.amt);
  const total = allocs.reduce((s, a) => s + a.amt, 0);
  const byCat = groupAllocByCat(allocs, cats);

  const full = new Date(date + 'T00:00:00').toLocaleDateString('en-SG', {
    weekday: 'long', day: 'numeric', month: 'long', year: 'numeric',
  });

  return (
    <div className="space-y-4">
      <button onClick={onBack} className="flex items-center gap-2 text-sm font-medium text-gray-500 active:text-gray-700">
        <ArrowLeft size={18} /> Back to insights
      </button>

      <div>
        <h2 className="text-xl font-semibold">{full}</h2>
      </div>

      <Card className="p-4 flex items-center justify-between">
        <div>
          <div className="text-xs text-gray-400 font-medium">Spent this day</div>
          <div className="text-2xl font-semibold tnum mt-0.5" style={{ color: ACCENT }}>{fmtSGD(total)}</div>
        </div>
        <div className="text-xs text-gray-400">{allocs.length} item{allocs.length === 1 ? '' : 's'}</div>
      </Card>

      {byCat.length > 1 && (
        <Card className="p-4 space-y-2">
          <div className="text-xs text-gray-400 font-medium">By category</div>
          {byCat.map((c) => (
            <div key={c.id} className="flex items-center justify-between text-sm">
              <div className="flex items-center gap-2"><Dot color={c.color} />{c.name}</div>
              <span className="tnum font-medium">{fmtSGD(c.value)}</span>
            </div>
          ))}
        </Card>
      )}

      {allocs.length === 0 ? (
        <div className="text-center text-gray-400 text-sm py-10">Nothing spent on this day.</div>
      ) : (
        <Card className="divide-y divide-gray-50">
          {allocs.map((a, i) => (
            <ExpenseRow key={a.e.id + ':' + i} e={a.e} cat={catById[a.e.catId]}
              amount={a.amt} note={(a.e.spreadDays || 1) > 1 ? 'daily share' : null}
              onClick={() => onEdit && onEdit(a.e)} />
          ))}
        </Card>
      )}
    </div>
  );
}

function groupByCat(expenses, cats) {
  const map = {};
  for (const e of expenses) map[e.catId] = (map[e.catId] || 0) + e.sgd;
  return Object.entries(map)
    .map(([id, value]) => {
      const c = cats.find((x) => x.id === id);
      return { id, value, name: c?.name || 'Other', color: c?.color || '#94A3B8' };
    })
    .sort((a, b) => b.value - a.value);
}

/* ----------------------------- TRIP INSIGHTS ----------------------------- */

function TripInsights({ data, cats, catById }) {
  const [tripId, setTripId] = useState(data.trips[0]?.id || null);
  const trip = data.trips.find((t) => t.id === tripId);

  return (
    <div className="space-y-4">
      {data.trips.length === 0 ? (
        <div className="text-center text-gray-400 text-sm py-10">
          No trips yet. Create one in the Trips tab, then your overseas spending shows up here.
        </div>
      ) : (
        <>
          <select value={tripId || ''} onChange={(e) => setTripId(e.target.value)}
            className="text-sm font-medium bg-white border border-gray-100 rounded-lg px-3 py-1.5 outline-none w-full">
            {data.trips.map((t) => <option key={t.id} value={t.id}>{(t.emoji || '✈️') + ' ' + t.name}</option>)}
          </select>
          {trip && <TripDetail trip={trip} data={data} cats={cats} catById={catById} />}
        </>
      )}
    </div>
  );
}

function TripDailyBreakdown({ exp, catById, col }) {
  const [page, setPage] = useState(0);
  const [openDay, setOpenDay] = useState(null);
  const dates = exp.map((e) => e.date).sort();
  if (!dates.length) return null;
  const start = dates[0], end = dates[dates.length - 1];
  const allDays = [];
  let d = new Date(start + 'T00:00:00');
  const ed = new Date(end + 'T00:00:00');
  while (d <= ed) { allDays.push(isoDate(d)); d.setDate(d.getDate() + 1); }

  const dayAmt = {};
  allDays.forEach((da) => { dayAmt[da] = 0; });
  for (const e of exp) for (const a of allocations(e)) if (a.date in dayAmt) dayAmt[a.date] += a.amt;
  const maxAmt = Math.max(1, ...allDays.map((da) => dayAmt[da]));

  const pages = [];
  for (let i = 0; i < allDays.length; i += 7) pages.push(allDays.slice(i, i + 7));
  const pageIdx = Math.min(page, pages.length - 1);
  const cur = pages[pageIdx] || [];

  const dayItems = (da) => {
    const items = [];
    for (const e of exp) for (const a of allocations(e)) if (a.date === da) items.push(a);
    return items.sort((x, y) => y.amt - x.amt);
  };

  return (
    <Card className="p-4">
      <div className="flex items-center justify-between mb-3">
        <div className="text-xs text-gray-400 font-medium">Spending by day · tap to expand</div>
        {pages.length > 1 && (
          <div className="flex items-center gap-2">
            <button onClick={() => setPage(Math.max(0, pageIdx - 1))} disabled={pageIdx === 0}
              style={{ color: pageIdx === 0 ? '#D1D5DB' : '#6B7280' }}><ChevronLeft size={16} /></button>
            <span className="text-xs text-gray-500">Week {pageIdx + 1}/{pages.length}</span>
            <button onClick={() => setPage(Math.min(pages.length - 1, pageIdx + 1))} disabled={pageIdx === pages.length - 1}
              style={{ color: pageIdx === pages.length - 1 ? '#D1D5DB' : '#6B7280' }}><ChevronRight size={16} /></button>
          </div>
        )}
      </div>
      <div className="space-y-1">
        {cur.map((da) => {
          const amt = dayAmt[da];
          const open = openDay === da;
          return (
            <div key={da}>
              <button onClick={() => setOpenDay(open ? null : da)} className="w-full flex items-center gap-3 py-1.5 active:opacity-70">
                <span className="text-xs text-gray-400 text-left shrink-0" style={{ width: 58 }}>
                  {new Date(da + 'T00:00:00').toLocaleDateString('en-SG', { weekday: 'short', day: 'numeric' })}
                </span>
                <div className="flex-1 h-2 rounded-full bg-gray-100 overflow-hidden">
                  <div className="h-full rounded-full" style={{ width: (amt / maxAmt * 100) + '%', background: col }} />
                </div>
                <span className="text-sm font-medium tnum text-right" style={{ width: 76 }}>{fmtSGD(amt)}</span>
              </button>
              {open && (
                <div className="pb-2" style={{ paddingLeft: 58 }}>
                  {dayItems(da).length === 0 ? (
                    <div className="text-xs text-gray-400 py-1">No spending this day.</div>
                  ) : dayItems(da).map((a, i) => (
                    <div key={i} className="flex items-center justify-between text-xs py-0.5">
                      <span className="text-gray-600 truncate flex items-center gap-1.5 min-w-0">
                        <Dot color={catById[a.e.catId]?.color || '#94A3B8'} />
                        <span className="truncate">{a.e.desc}{(a.e.spreadDays || 1) > 1 ? ' · daily share' : ''}</span>
                      </span>
                      <span className="tnum text-gray-500 ml-2 shrink-0">{fmtSGD(a.amt)}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          );
        })}
      </div>
    </Card>
  );
}

function TripDetail({ trip, data, cats, catById }) {
  const exp = data.expenses.filter((e) => e.tripId === trip.id);
  const total = exp.reduce((s, e) => s + e.sgd, 0);
  const dates = exp.map((e) => e.date).sort();
  const days = dates.length
    ? Math.max(1, Math.round((new Date(dates[dates.length - 1]) - new Date(dates[0])) / 86400000) + 1)
    : 1;
  const byCat = groupByCat(exp, cats);

  // by original currency
  const curMap = {};
  for (const e of exp) curMap[e.currency] = (curMap[e.currency] || 0) + e.original;
  const col = trip.color || ACCENT;

  return (
    <div className="space-y-4">
      <div className="rounded-2xl p-4 text-white flex items-center gap-3"
        style={{ background: `linear-gradient(135deg, ${col}, ${col}cc)` }}>
        <div className="w-12 h-12 rounded-xl flex items-center justify-center text-2xl shrink-0"
          style={{ background: 'rgba(255,255,255,0.22)' }}>{trip.emoji || '✈️'}</div>
        <div>
          <div className="text-lg font-bold leading-tight">{trip.name}</div>
          <div className="text-sm opacity-90">{trip.currency} · {fmtSGD(total)}</div>
        </div>
      </div>
      <div className="flex gap-3">
        <StatTile label="Trip total" value={fmtSGD(total)} tone={col} />
        <StatTile label="Daily avg" value={fmtSGD(total / days)} sub={`${days} day${days === 1 ? '' : 's'}`} />
      </div>
      <div className="flex gap-3">
        <StatTile label="Items" value={String(exp.length)} />
        <StatTile label="Home currency" value="SGD" sub={`paid in ${Object.keys(curMap).length || 1}`} />
      </div>

      {Object.keys(curMap).length > 0 && (
        <Card className="p-4">
          <div className="text-xs text-gray-400 font-medium mb-2">Spent by currency</div>
          <div className="space-y-1.5">
            {Object.entries(curMap).map(([c, v]) => (
              <div key={c} className="flex items-center justify-between text-sm">
                <span className="font-medium">{c}</span>
                <span className="tnum text-gray-600">{fmtNum(v, c)}
                  <span className="text-gray-400 ml-2">≈ {fmtSGD(toBase(v, c, data.rates))}</span></span>
              </div>
            ))}
          </div>
        </Card>
      )}

      {total > 0 && (
        <Card className="p-4">
          <div className="text-xs text-gray-400 font-medium mb-1">Where it went</div>
          <DonutChart data={byCat} total={total} caption="Trip total" />
          <div className="space-y-2 mt-1">
            {byCat.map((c) => (
              <div key={c.id} className="flex items-center justify-between text-sm">
                <div className="flex items-center gap-2"><Dot color={c.color} />{c.name}</div>
                <div className="tnum font-medium">{fmtSGD(c.value)}</div>
              </div>
            ))}
          </div>
        </Card>
      )}

      {total > 0 && <TripDailyBreakdown exp={exp} catById={catById} col={col} />}

      {total === 0 && (
        <div className="text-center text-gray-400 text-sm py-8">
          No expenses on this trip yet. Set it active in Trips, then log as you go.
        </div>
      )}
    </div>
  );
}

