/* ----------------------------- HISTORY ----------------------------- */

function SwipeRow({ children, onDelete }) {
  const [dx, setDx] = useState(0);
  const [removing, setRemoving] = useState(false);
  const rowRef = useRef(null);
  const startX = useRef(0);
  const startY = useRef(0);
  const dir = useRef(null);     // 'h' | 'v' | null  (lock after first move)
  const moved = useRef(false);  // did a real horizontal drag happen?
  const dragging = useRef(false);
  const widthRef = useRef(320);
  const thresh = () => Math.min(170, widthRef.current * 0.5); // swipe past here = delete

  const down = (e) => {
    if (e.pointerType === 'mouse' && e.button !== 0) return;
    dragging.current = true; moved.current = false; dir.current = null;
    startX.current = e.clientX; startY.current = e.clientY;
    if (rowRef.current) widthRef.current = rowRef.current.offsetWidth || 320;
  };
  const move = (e) => {
    if (!dragging.current) return;
    const ddx = e.clientX - startX.current;
    const ddy = e.clientY - startY.current;
    if (!dir.current) {
      if (Math.abs(ddx) < 6 && Math.abs(ddy) < 6) return;
      dir.current = Math.abs(ddx) > Math.abs(ddy) ? 'h' : 'v';
      if (dir.current === 'h') { try { e.currentTarget.setPointerCapture(e.pointerId); } catch (err) {} }
    }
    if (dir.current !== 'h') return; // vertical → let the page scroll
    moved.current = true;
    let d = ddx; if (d > 0) d = 0;
    setDx(d);
  };
  const finish = () => {
    if (!dragging.current) return;
    dragging.current = false;
    if (dir.current === 'h' && -dx >= thresh()) {
      setRemoving(true);
      setDx(-(widthRef.current + 40));
      setTimeout(onDelete, 200);
    } else {
      setDx(0);
    }
    dir.current = null;
    setTimeout(() => { moved.current = false; }, 30);
  };

  const past = -dx >= thresh();
  return (
    <div ref={rowRef} className="relative overflow-hidden"
      style={{ maxHeight: removing ? 0 : 500, opacity: removing ? 0.3 : 1, transition: removing ? 'max-height 0.2s ease, opacity 0.2s ease' : 'none' }}>
      <div className="absolute inset-0 flex items-center justify-end pr-5"
        style={{ background: past ? '#DC2626' : '#FCA5A5', transition: 'background 0.12s' }}>
        {past && <span className="text-white font-semibold mr-2" style={{ fontSize: 12 }}>release to delete</span>}
        <Trash2 size={past ? 22 : 18} color="#fff" style={{ transition: 'all 0.12s' }} />
      </div>
      <div className="bg-white"
        onPointerDown={down} onPointerMove={move} onPointerUp={finish} onPointerCancel={finish}
        onClickCapture={(ev) => { if (moved.current) { ev.preventDefault(); ev.stopPropagation(); } }}
        style={{ transform: `translateX(${dx}px)`, transition: dragging.current ? 'none' : 'transform 0.2s', touchAction: 'pan-y' }}>
        {children}
      </div>
    </div>
  );
}

// Export every transaction to an .xlsx workbook: a Summary sheet + one sheet per month.
function exportAllExcel(data, cats) {
  const catName = (id) => (cats.find((c) => c.id === id) || {}).name || '';
  const subName = (id, sid) => {
    const c = cats.find((x) => x.id === id);
    const s = c && (c.subs || []).find((x) => x.id === sid);
    return s ? s.name : '';
  };
  const tripName = (id) => (data.trips.find((t) => t.id === id) || {}).name || '';
  const r2 = (n) => Math.round((n || 0) * 100) / 100;

  const wb = XLSX.utils.book_new();

  const byCat = {}, byMonth = {};
  for (const e of data.expenses) {
    byCat[e.catId] = (byCat[e.catId] || 0) + e.sgd;
    const k = monthKey(e.date);
    byMonth[k] = (byMonth[k] || 0) + e.sgd;
  }
  const catRows = Object.entries(byCat).map(([id, v]) => [catName(id) || id, r2(v)]).sort((a, b) => b[1] - a[1]);
  const monthKeys = Object.keys(byMonth).sort();
  const grand = Object.values(byCat).reduce((s, v) => s + v, 0);

  const summary = [
    ['Expense Tracker — full export'],
    ['Generated', new Date().toLocaleString('en-SG')],
    ['Total spent (SGD)', r2(grand)],
    [],
    ['Spending by category', 'Total (SGD)'],
    ...catRows,
    [],
    ['Spending by month', 'Total (SGD)'],
    ...monthKeys.map((k) => [prettyMonth(k), r2(byMonth[k])]),
  ];
  XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(summary), 'Summary');

  for (const k of monthKeys) {
    const rows = data.expenses
      .filter((e) => monthKey(e.date) === k)
      .sort((a, b) => (a.date < b.date ? -1 : a.date > b.date ? 1 : 0))
      .map((e) => ({
        Date: e.date,
        Description: e.desc || '',
        Category: catName(e.catId),
        Subcategory: subName(e.catId, e.subId),
        'Original amount': r2(e.original),
        Currency: e.currency,
        'SGD amount': r2(e.sgd),
        Trip: tripName(e.tripId),
      }));
    let name = prettyMonth(k);
    if (name.length > 31) name = k;
    XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(rows), name);
  }

  XLSX.writeFile(wb, 'expense-tracker-export.xlsx');
}

function MonthlyWrap({ data, cats, catById, onBack, onEdit }) {
  const [anchor, setAnchor] = useState(todayISO());
  const today = todayISO();
  const [start, end] = periodRange('month', anchor);
  const isCurrent = today >= start && today <= end;
  const isFuture = start > today;
  const sx = useRef(null);

  const allocs = allocInRange(data.expenses, (ds) => ds >= start && ds <= end);
  const total = allocs.reduce((s, a) => s + a.amt, 0);
  const byCat = groupAllocByCat(allocs, cats);

  const monthExp = data.expenses.filter((e) => e.date >= start && e.date <= end);
  const txCount = monthExp.length;
  const biggest = monthExp.reduce((m, e) => (!m || e.sgd > m.sgd ? e : m), null);
  const span = daysBetween(start, end) + 1;
  const elapsed = isCurrent ? daysBetween(start, today) + 1 : span;
  const perDay = elapsed ? total / elapsed : 0;

  const go = (dir) => { if (dir > 0 && isCurrent) return; setAnchor((a) => shiftAnchor('month', a, dir)); };
  const onTouchStart = (e) => { sx.current = e.touches[0].clientX; };
  const onTouchEnd = (e) => {
    if (sx.current == null) return;
    const dx = e.changedTouches[0].clientX - sx.current;
    if (dx > 50) go(-1); else if (dx < -50) go(1);
    sx.current = null;
  };

  return (
    <div className="space-y-4" onTouchStart={onTouchStart} onTouchEnd={onTouchEnd}>
      <button onClick={onBack} className="flex items-center gap-1.5 text-sm font-medium" style={{ color: ACCENT }}>
        <ArrowLeft size={16} /> Back to history
      </button>

      <div className="flex items-center justify-between">
        <button onClick={() => go(-1)} className="w-9 h-9 rounded-full bg-white border border-gray-100 flex items-center justify-center text-gray-500 active:scale-90">
          <ChevronLeft size={18} />
        </button>
        <div className="text-center">
          <div className="text-lg font-bold">{periodLabelLong('month', anchor)}</div>
          {isCurrent && (
            <span className="inline-block mt-0.5 text-xs font-semibold px-2 py-0.5 rounded-full" style={{ color: ACCENT, background: ACCENT + '18' }}>
              In progress
            </span>
          )}
        </div>
        <button onClick={() => go(1)} disabled={isCurrent}
          className="w-9 h-9 rounded-full bg-white border border-gray-100 flex items-center justify-center active:scale-90"
          style={{ color: isCurrent ? '#D1D5DB' : '#6B7280' }}>
          <ChevronRight size={18} />
        </button>
      </div>

      <div className="flex justify-center">
        <input type="month" value={monthKey(anchor)} max={monthKey(today)}
          onChange={(e) => e.target.value && setAnchor(e.target.value + '-01')}
          className="px-3 py-1.5 rounded-lg bg-gray-50 border border-gray-200 outline-none text-sm text-gray-500" />
      </div>

      {data.expenses.length > 0 && (
        <button onClick={() => exportAllExcel(data, cats)}
          className="w-full flex items-center justify-center gap-2 px-4 py-2.5 rounded-xl bg-gray-50 text-sm font-medium text-gray-600 active:scale-[0.99]">
          <Download size={15} /> Export all transactions to Excel
        </button>
      )}

      {isFuture || total === 0 ? (
        <Card className="p-8 text-center">
          <div className="text-gray-300 text-sm">{isFuture ? 'This month hasn\u2019t started yet.' : 'No spending logged this month.'}</div>
        </Card>
      ) : (
        <>
          <Card className="p-4">
            <DonutChart data={byCat} total={total} caption={isCurrent ? 'spent so far' : 'total spent'} onSlice={null} />
            <div className="grid grid-cols-2 gap-3 mt-2">
              <StatTile label={isCurrent ? 'Per day so far' : 'Avg per day'} value={fmtSGD(perDay)} />
              <StatTile label="Transactions" value={txCount} />
            </div>
          </Card>

          <Card className="p-4">
            <div className="text-xs text-gray-400 font-medium mb-3">Where it went</div>
            <div className="space-y-2.5">
              {byCat.map((c) => (
                <div key={c.id} className="flex items-center gap-3">
                  <Dot color={c.color} />
                  <div className="text-sm flex-1 truncate">{c.name}</div>
                  <div className="text-sm font-semibold tnum">{fmtSGD(c.value)}</div>
                  <div className="text-xs text-gray-400 tnum w-10 text-right">{Math.round((c.value / total) * 100)}%</div>
                </div>
              ))}
            </div>
          </Card>

          {biggest && (
            <ExtremeCard label="Biggest single expense" exp={biggest} catById={catById} onClick={() => onEdit(biggest)} />
          )}

          {isCurrent && (
            <div className="text-center text-xs text-gray-400 px-6">
              This wrap updates as the month goes on — check back at month-end for the full picture.
            </div>
          )}
        </>
      )}
    </div>
  );
}

function HistoryTab({ data, cats, catById, onEdit, onDelete, onDeleteMany }) {
  const [q, setQ] = useState('');
  const [selCats, setSelCats] = useState([]); // empty = all
  const [showFilters, setShowFilters] = useState(false);
  const [from, setFrom] = useState('');
  const [to, setTo] = useState('');
  const [showUpcoming, setShowUpcoming] = useState(false);
  const [showWrap, setShowWrap] = useState(false);
  const [selectMode, setSelectMode] = useState(false);
  const [sel, setSel] = useState([]); // selected expense ids
  const paintVal = useRef(null);
  const painting = useRef(false);
  const today = todayISO();

  if (showWrap) return <MonthlyWrap data={data} cats={cats} catById={catById} onEdit={onEdit} onBack={() => setShowWrap(false)} />;

  const inSel = (id) => sel.includes(id);
  const setOne = (id, val) => setSel((s) => {
    const has = s.includes(id);
    if (val && !has) return [...s, id];
    if (!val && has) return s.filter((x) => x !== id);
    return s;
  });
  const toggleOne = (id) => setOne(id, !inSel(id));
  const exitSelect = () => { setSelectMode(false); setSel([]); };

  // drag-to-paint selection — only starts when the press begins on a checkbox
  const onRowsDown = (e) => {
    if (!selectMode) return;
    const cb = e.target.closest && e.target.closest('[data-cb]');
    const row = e.target.closest && e.target.closest('[data-exp-id]');
    if (!cb || !row) return;
    const id = row.getAttribute('data-exp-id');
    const val = !inSel(id);
    paintVal.current = val; painting.current = true;
    setOne(id, val);
    try { e.currentTarget.setPointerCapture(e.pointerId); } catch (err) {}
    e.preventDefault();
  };
  const onRowsMove = (e) => {
    if (!painting.current) return;
    const el = document.elementFromPoint(e.clientX, e.clientY);
    const row = el && el.closest && el.closest('[data-exp-id]');
    if (row) setOne(row.getAttribute('data-exp-id'), paintVal.current);
  };
  const onRowsUp = () => { painting.current = false; };

  const toggleCat = (id) =>
    setSelCats((s) => (s.includes(id) ? s.filter((x) => x !== id) : [...s, id]));

  const match = (e) => {
    if (selCats.length && !selCats.includes(e.catId)) return false;
    if (q && !(e.desc.toLowerCase().includes(q.toLowerCase()))) return false;
    if (from && e.date < from) return false;
    if (to && e.date > to) return false;
    return true;
  };
  const filtered = data.expenses.filter(match);
  const past = filtered.filter((e) => e.date <= today);
  const future = filtered.filter((e) => e.date > today).sort((a, b) => (a.date < b.date ? -1 : a.date > b.date ? 1 : 0));
  const recurUp = (data.recurring || [])
    .filter((r) => r.active && (selCats.length === 0 || selCats.includes(r.catId)) && (!q || r.desc.toLowerCase().includes(q.toLowerCase())))
    .map((r) => ({ r, date: upcomingOf(r) }))
    .filter((x) => x.date)
    .sort((a, b) => (a.date < b.date ? -1 : 1));

  const groups = {};
  for (const e of past) (groups[e.date] = groups[e.date] || []).push(e);
  const dates = Object.keys(groups).sort().reverse();
  const upcomingCount = future.length + recurUp.length;
  const filtersOn = from || to || selCats.length > 0;

  return (
    <div className="space-y-4">
      <button onClick={() => setShowWrap(true)}
        className="w-full flex items-center justify-between px-4 py-3 rounded-2xl text-white active:scale-[0.99] transition"
        style={{ background: `linear-gradient(135deg, ${ACCENT}, ${ACCENT}cc)` }}>
        <span className="flex items-center gap-2 text-sm font-semibold">
          <BarChart3 size={16} /> Monthly Wrap
        </span>
        <ChevronRight size={18} />
      </button>

      <div className="flex items-center gap-2">
        <div className="flex items-center gap-2 px-3 py-2 rounded-xl bg-white border border-gray-100 flex-1">
          <Search size={16} className="text-gray-300" />
          <input value={q} onChange={(e) => setQ(e.target.value)} placeholder="Search expenses"
            className="flex-1 outline-none text-sm bg-transparent" />
          {q && <button onClick={() => setQ('')}><X size={15} className="text-gray-300" /></button>}
        </div>
        <button onClick={() => setShowFilters((v) => !v)}
          className="px-3 py-2 rounded-xl border text-sm font-medium"
          style={(showFilters || filtersOn)
            ? { background: ACCENT, borderColor: ACCENT, color: '#fff' }
            : { background: '#fff', borderColor: '#E5E7EB', color: '#6B7280' }}>
          Filters{filtersOn ? ' •' : ''}
        </button>
        <button onClick={() => (selectMode ? exitSelect() : setSelectMode(true))}
          className="px-3 py-2 rounded-xl border text-sm font-medium"
          style={selectMode
            ? { background: ACCENT, borderColor: ACCENT, color: '#fff' }
            : { background: '#fff', borderColor: '#E5E7EB', color: '#6B7280' }}>
          {selectMode ? 'Done' : 'Select'}
        </button>
      </div>

      {showFilters && (
        <Card className="p-3 space-y-3">
          <div>
            <div className="text-xs text-gray-400 font-medium mb-2">Categories (tap to combine)</div>
            <div className="flex gap-2 overflow-x-auto noscroll pb-1">
              <Chip on={selCats.length === 0} onClick={() => setSelCats([])} label="All" />
              {cats.map((c) => (
                <Chip key={c.id} on={selCats.includes(c.id)} color={c.color}
                  onClick={() => toggleCat(c.id)} label={c.name} />
              ))}
            </div>
          </div>
          <div>
            <div className="text-xs text-gray-400 font-medium mb-2">Date range</div>
            <div className="flex items-center gap-2">
              <input type="date" value={from} onChange={(e) => setFrom(e.target.value)}
                className="flex-1 min-w-0 px-2 py-1.5 rounded-lg bg-gray-50 border border-gray-200 outline-none text-sm" />
              <span className="text-gray-400 text-sm">to</span>
              <input type="date" value={to} onChange={(e) => setTo(e.target.value)}
                className="flex-1 min-w-0 px-2 py-1.5 rounded-lg bg-gray-50 border border-gray-200 outline-none text-sm" />
            </div>
          </div>
          {filtersOn && (
            <button onClick={() => { setSelCats([]); setFrom(''); setTo(''); }}
              className="text-xs text-gray-400 underline">Clear filters</button>
          )}
        </Card>
      )}

      {upcomingCount > 0 && (
        <div>
          <button onClick={() => setShowUpcoming((v) => !v)}
            className="w-full flex items-center justify-between px-4 py-3 rounded-2xl bg-white border app-card"
            style={{ borderColor: ACCENT + '40' }}>
            <span className="flex items-center gap-2 text-sm font-semibold" style={{ color: ACCENT }}>
              <Calendar size={15} /> Upcoming Expenses ({upcomingCount})
            </span>
            <ChevronDown size={18} className="text-gray-400"
              style={{ transform: showUpcoming ? 'rotate(180deg)' : 'none', transition: 'transform 0.2s' }} />
          </button>
          {showUpcoming && (
            <Card className="divide-y divide-gray-50 mt-2">
              {future.map((e) => (
                <ExpenseRow key={e.id} e={e} cat={catById[e.catId]} note={`scheduled · ${prettyDate(e.date)}`} onClick={() => onEdit(e)} />
              ))}
              {recurUp.map(({ r, date }) => (
                <div key={r.id} className="flex items-center gap-3 px-4 py-3">
                  <Dot color={catById[r.catId]?.color || '#94A3B8'} />
                  <div className="flex-1 min-w-0">
                    <div className="text-sm font-medium truncate">
                      {r.desc}
                      <span className="ml-1.5 text-xs font-medium px-1.5 py-0.5 rounded" style={{ color: ACCENT, background: ACCENT + '14' }}>
                        repeats {r.freq === 'weekly' ? 'weekly' : 'monthly'}
                      </span>
                    </div>
                    <div className="text-xs text-gray-400">next {prettyDate(date)} · manage in Settings</div>
                  </div>
                  <div className="text-sm font-semibold tnum">{fmtSGD(toBase(r.original, r.currency, data.rates))}</div>
                </div>
              ))}
            </Card>
          )}
        </div>
      )}

      {dates.length === 0 ? (
        <div className="text-center text-gray-400 text-sm py-10">
          {filtersOn || q ? 'Nothing matches your search or filters.' : 'No expenses logged yet.'}
        </div>
      ) : (
        <div className="space-y-4" onPointerDown={onRowsDown} onPointerMove={onRowsMove} onPointerUp={onRowsUp} onPointerCancel={onRowsUp}>
          {dates.map((d) => {
            const dayTotal = groups[d].reduce((s, e) => s + e.sgd, 0);
            return (
              <div key={d}>
                <div className="flex items-center justify-between px-1 mb-1.5">
                  <span className="text-xs font-medium text-gray-400">{prettyDate(d)}</span>
                  <span className="text-xs font-medium text-gray-400 tnum">{fmtSGD(dayTotal)}</span>
                </div>
                <Card className="divide-y divide-gray-50 overflow-hidden">
                  {groups[d].map((e) => (
                    selectMode ? (
                      <div key={e.id} data-exp-id={e.id} style={{ touchAction: 'pan-y' }}>
                        <ExpenseRow e={e} cat={catById[e.catId]} selected={inSel(e.id)} onClick={() => toggleOne(e.id)}
                          lead={
                            <span data-cb className="shrink-0 flex items-center justify-center" style={{ width: 22, height: 22 }}>
                              <span style={{ width: 21, height: 21, borderRadius: 21, border: '2px solid',
                                borderColor: inSel(e.id) ? ACCENT : '#D1D5DB', background: inSel(e.id) ? ACCENT : 'transparent',
                                display: 'flex', alignItems: 'center', justifyContent: 'center', transition: 'all 0.1s' }}>
                                {inSel(e.id) && <Check size={13} color="#fff" />}
                              </span>
                            </span>
                          } />
                      </div>
                    ) : (
                      <SwipeRow key={e.id} onDelete={() => onDelete(e.id)}>
                        <ExpenseRow e={e} cat={catById[e.catId]} onClick={() => onEdit(e)} />
                      </SwipeRow>
                    )
                  ))}
                </Card>
              </div>
            );
          })}
          {!selectMode && (
            <div className="text-center text-gray-300" style={{ fontSize: 11 }}>Swipe a row left to delete · or tap “Select” for many</div>
          )}
          {selectMode && <div style={{ height: 72 }} />}
        </div>
      )}

      {selectMode && (
        <div className="fixed left-0 right-0 bottom-0 px-4 pb-5 pt-3" style={{ zIndex: 50, background: 'linear-gradient(to top, rgba(0,0,0,0.06), transparent)' }}>
          <div className="max-w-md mx-auto flex items-center gap-2 px-3 py-2.5 rounded-2xl bg-white border border-gray-100" style={{ boxShadow: '0 8px 30px rgba(0,0,0,0.16)' }}>
            <button onClick={() => { const ids = past.map((e) => e.id); setSel(sel.length === ids.length ? [] : ids); }}
              className="text-sm font-medium px-2 py-1.5 rounded-lg active:bg-gray-50" style={{ color: ACCENT }}>
              {sel.length === past.length && past.length > 0 ? 'Clear' : 'All'}
            </button>
            <div className="flex-1 text-center text-sm font-medium text-gray-500">{sel.length} selected</div>
            <button disabled={sel.length === 0}
              onClick={() => { onDeleteMany(sel); exitSelect(); }}
              className="flex items-center gap-1.5 text-sm font-semibold px-3.5 py-2 rounded-xl active:scale-95 transition"
              style={sel.length === 0 ? { background: '#F3F4F6', color: '#9CA3AF' } : { background: '#DC2626', color: '#fff' }}>
              <Trash2 size={15} /> Delete
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

function Chip({ on, onClick, label, color }) {
  return (
    <button onClick={onClick}
      className="shrink-0 flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-sm font-medium border transition"
      style={on
        ? { background: color || '#1B2420', borderColor: color || '#1B2420', color: '#fff' }
        : { background: '#fff', borderColor: '#F0F0F0', color: '#6B7280' }}>
      {color && <Dot color={on ? '#fff' : color} />}{label}
    </button>
  );
}

function Segmented({ value, onChange, options }) {
  return (
    <div className="flex p-1 rounded-xl bg-gray-100">
      {options.map((o) => (
        <button key={o.v} onClick={() => onChange(o.v)}
          className="flex-1 py-2 rounded-lg text-sm font-medium transition"
          style={value === o.v ? { background: '#fff', color: '#1B2420' } : { color: '#9CA3AF' }}>
          {o.label}
        </button>
      ))}
    </div>
  );
}

/* ----------------------------- EDIT SHEET ----------------------------- */

function EditSheet({ expense, cats, rates, trips, onClose, onSave, onDelete }) {
  const [e, setE] = useState({ ...expense });
  const cat = cats.find((c) => c.id === e.catId);
  const set = (p) => setE((x) => ({ ...x, ...p }));

  const save = () => {
    onSave({ ...e, original: parseFloat(e.original) || 0, sgd: toBase(parseFloat(e.original) || 0, e.currency, rates) });
  };

  return (
    <div className="fixed inset-0 z-40 flex items-end justify-center" style={{ background: 'rgba(0,0,0,0.35)' }} onClick={onClose}>
      <div className="bg-white w-full max-w-md rounded-t-3xl p-5 space-y-4" onClick={(ev) => ev.stopPropagation()}>
        <div className="flex items-center justify-between">
          <h3 className="font-semibold text-lg">Edit expense</h3>
          <button onClick={onClose} className="p-1 text-gray-400"><X size={20} /></button>
        </div>

        <input value={e.desc} onChange={(ev) => set({ desc: ev.target.value })}
          className="w-full px-3 py-2.5 rounded-xl bg-gray-50 outline-none" placeholder="Description" />

        <div className="flex gap-2">
          <div className="flex items-center gap-1 px-3 py-2 rounded-xl bg-gray-50 flex-1">
            <span className="text-gray-400 text-sm">{SYMBOLS[e.currency] || e.currency}</span>
            <input inputMode="decimal" value={e.original}
              onChange={(ev) => set({ original: ev.target.value.replace(/[^\d.]/g, '') })}
              className="w-full bg-transparent outline-none tnum" />
          </div>
          <select value={e.currency} onChange={(ev) => set({ currency: ev.target.value })}
            className="px-3 py-2 rounded-xl bg-gray-50 text-sm font-medium outline-none">
            {Object.keys(rates).map((c) => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>

        <div className="flex flex-wrap gap-2">
          {cats.map((c) => (
            <button key={c.id} onClick={() => set({ catId: c.id, subId: null })}
              className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-sm border"
              style={e.catId === c.id
                ? { background: c.color, borderColor: c.color, color: '#fff' }
                : { background: '#fff', borderColor: '#F0F0F0', color: '#6B7280' }}>
              <Dot color={e.catId === c.id ? '#fff' : c.color} />{c.name}
            </button>
          ))}
        </div>

        {cat && cat.subs.length > 0 && (
          <div className="flex flex-wrap gap-2">
            {cat.subs.map((s) => (
              <button key={s.id} onClick={() => set({ subId: e.subId === s.id ? null : s.id })}
                className="px-3 py-1.5 rounded-lg text-sm border"
                style={e.subId === s.id
                  ? { background: '#1B2420', borderColor: '#1B2420', color: '#fff' }
                  : { background: '#fff', borderColor: '#F0F0F0', color: '#6B7280' }}>
                {s.name}
              </button>
            ))}
          </div>
        )}

        <input type="date" value={e.date}
          onChange={(ev) => set({ date: ev.target.value })}
          className="px-3 py-2 rounded-xl bg-gray-50 text-sm outline-none w-full" />

        <select value={e.tripId || ''} onChange={(ev) => set({ tripId: ev.target.value || null })}
          className="px-3 py-2 rounded-xl bg-gray-50 text-sm outline-none w-full">
          <option value="">No trip (everyday)</option>
          {trips.map((t) => <option key={t.id} value={t.id}>{t.name}</option>)}
        </select>

        <div className="rounded-xl bg-gray-50 p-3">
          <div className="flex items-center justify-between">
            <span className="text-sm text-gray-500">Split cost over</span>
            <div className="flex items-center gap-1.5">
              <input inputMode="numeric" value={e.spreadDays || 1}
                onChange={(ev) => set({ spreadDays: Math.max(1, parseInt(ev.target.value.replace(/[^\d]/g, '')) || 1) })}
                className="w-14 px-2 py-1 rounded-lg bg-white border border-gray-200 outline-none text-sm tnum text-center" />
              <span className="text-sm text-gray-500">days</span>
            </div>
          </div>
          {(e.spreadDays || 1) > 1 && (
            <>
              <div className="flex items-center justify-between mt-2">
                <span className="text-sm text-gray-500">Starting on</span>
                <input type="date" value={e.spreadStart || e.date}
                  onChange={(ev) => set({ spreadStart: ev.target.value })}
                  className="px-2.5 py-1.5 rounded-lg bg-white border border-gray-200 outline-none text-sm" />
              </div>
              <div className="text-xs text-gray-400 mt-1.5 tnum">
                ≈ {fmtSGD(toBase(parseFloat(e.original) || 0, e.currency, rates) / (e.spreadDays || 1))}/day from {prettyDate(e.spreadStart || e.date)}
              </div>
            </>
          )}
        </div>

        <div className="flex gap-2 pt-1">
          <button onClick={() => onDelete(e.id)} className="px-4 py-3 rounded-xl bg-red-50 text-red-500 font-medium flex items-center gap-1.5">
            <Trash2 size={16} /> Delete
          </button>
          <button onClick={save} className="flex-1 py-3 rounded-xl text-white font-semibold" style={{ background: ACCENT }}>
            Save changes
          </button>
        </div>
      </div>
    </div>
  );
}

/* ----------------------------- SETTINGS ----------------------------- */

function SettingsTab({ data, update, setData, onSignOut }) {
  const [open, setOpen] = useState(null); // 'cats' | 'rates' | 'budget' | 'data'
  return (
    <div className="space-y-3">
      <SettingRow icon={<Layers size={18} />} title="Categories" desc="Add, rename, recolor, or remove"
        open={open === 'cats'} onClick={() => setOpen(open === 'cats' ? null : 'cats')}>
        <CategoryEditor data={data} update={update} />
      </SettingRow>

      <SettingRow icon={<CreditCard size={18} />} title="Currencies & rates" desc="Rough rates used for trips"
        open={open === 'rates'} onClick={() => setOpen(open === 'rates' ? null : 'rates')}>
        <RatesEditor data={data} update={update} />
      </SettingRow>

      <SettingRow icon={<Wallet size={18} />} title="Default currency" desc={`Totals shown in ${data.baseCurrency || 'SGD'}`}
        open={open === 'basecur'} onClick={() => setOpen(open === 'basecur' ? null : 'basecur')}>
        <div className="space-y-2">
          <div className="text-xs text-gray-400">The currency your totals display in, and the default for new expenses. Changing it only affects expenses you log from now on — past expenses keep the value they were recorded with, and nothing is re-converted.</div>
          <div className="grid grid-cols-3 gap-2">
            {Object.keys(data.rates || DEFAULT_RATES).map((c) => (
              <button key={c} onClick={() => update({ baseCurrency: c })}
                className="px-2 py-2 rounded-xl border text-sm flex items-center justify-center gap-1"
                style={(data.baseCurrency || 'SGD') === c
                  ? { background: ACCENT + '12', borderColor: ACCENT, color: 'var(--ink)', fontWeight: 600 }
                  : { background: '#fff', borderColor: '#EEE', color: '#6B7280' }}>
                <span>{SYMBOLS[c] || ''}</span><span>{c}</span>
              </button>
            ))}
          </div>
        </div>
      </SettingRow>

      <SettingRow icon={<Wallet size={18} />} title="Budgets" desc={(() => { const b = data.budgets || {}; const on = ['week', 'month', 'year'].filter((k) => b[k] > 0); return on.length ? on.map((k) => k === 'week' ? 'weekly' : k === 'year' ? 'yearly' : 'monthly').join(', ') : 'Optional · not set'; })()}
        open={open === 'budget'} onClick={() => setOpen(open === 'budget' ? null : 'budget')}>
        <BudgetEditor data={data} update={update} />
      </SettingRow>

      <SettingRow icon={<Layers size={18} />} title="Default expense sort" desc={SORTS[data.defaultSort || 'amount_desc'].label}
        open={open === 'sort'} onClick={() => setOpen(open === 'sort' ? null : 'sort')}>
        <div className="space-y-2">
          <div className="text-xs text-gray-400">How expense lists are ordered by default in Insights and category views.</div>
          {Object.entries(SORTS).map(([k, o]) => (
            <button key={k} onClick={() => update({ defaultSort: k })}
              className="w-full flex items-center justify-between px-3 py-2.5 rounded-xl border text-sm"
              style={(data.defaultSort || 'amount_desc') === k
                ? { background: ACCENT + '12', borderColor: ACCENT, color: 'var(--ink)', fontWeight: 600 }
                : { background: '#fff', borderColor: '#EEE', color: '#6B7280' }}>
              {o.label}
              {(data.defaultSort || 'amount_desc') === k && <Check size={16} style={{ color: ACCENT }} />}
            </button>
          ))}
        </div>
      </SettingRow>

      <SettingRow icon={<Palette size={18} />} title="Appearance" desc="Background, font, size & contrast"
        open={open === 'appear'} onClick={() => setOpen(open === 'appear' ? null : 'appear')}>
        <AppearanceEditor data={data} update={update} />
      </SettingRow>

      <SettingRow icon={<RotateCcw size={18} />} title="Recurring expenses" desc={`${(data.recurring || []).filter((r) => r.active).length} active`}
        open={open === 'recur'} onClick={() => setOpen(open === 'recur' ? null : 'recur')}>
        <RecurringEditor data={data} update={update} />
      </SettingRow>

      <SettingRow icon={<Download size={18} />} title="Backup & export" desc="Download CSV or a backup file"
        open={open === 'data'} onClick={() => setOpen(open === 'data' ? null : 'data')}>
        <DataTools data={data} setData={setData} />
      </SettingRow>

      {onSignOut && (
        <button onClick={onSignOut}
          className="w-full mt-2 py-2.5 rounded-xl text-sm font-medium border active:scale-95 transition"
          style={{ borderColor: '#FCA5A5', color: '#DC2626', background: '#fff' }}>
          Log out
        </button>
      )}

      <p className="text-xs text-gray-400 text-center pt-4 px-6">
        Totals are shown in {data.baseCurrency || 'SGD'}. Your expenses sync privately to your account — only you can see them. Export a backup now and then for extra peace of mind.
      </p>

      <DangerZone data={data} update={update} />

      <TechStackEgg />
    </div>
  );
}

