function RecurringEditor({ data, update }) {
  const rules = data.recurring || [];
  const active = rules.filter((r) => r.active);
  const stop = (id) => update({ recurring: rules.filter((r) => r.id !== id) });
  if (active.length === 0) {
    return <div className="text-sm text-gray-400">No recurring expenses yet. When adding one, tap “Special Expense” then “Repeat”.</div>;
  }
  return (
    <div className="space-y-2">
      <div className="text-xs text-gray-400">Already-logged entries stay in your history — stopping only prevents future ones.</div>
      {active.map((r) => {
        const cat = data.categories.find((c) => c.id === r.catId);
        return (
          <div key={r.id} className="flex items-center gap-3 p-3 rounded-xl bg-gray-50">
            <Dot color={cat?.color || '#94A3B8'} />
            <div className="flex-1 min-w-0">
              <div className="text-sm font-medium truncate">{r.desc}</div>
              <div className="text-xs text-gray-400">
                {fmtNum(r.original, r.currency)} · {r.freq === 'weekly' ? 'weekly' : 'monthly'} · next {prettyDate(upcomingOf(r))}
              </div>
            </div>
            <button onClick={() => stop(r.id)} className="text-xs text-red-500 font-medium px-2.5 py-1.5 rounded-lg bg-red-50">Stop</button>
          </div>
        );
      })}
    </div>
  );
}

