function BudgetEditor({ data, update }) {
  const b = data.budgets || { week: 0, month: data.budget || 0, year: 0 };
  const [week, setWeek] = useState(b.week || '');
  const [month, setMonth] = useState(b.month || '');
  const [year, setYear] = useState(b.year || '');
  const save = () => {
    const budgets = { week: parseFloat(week) || 0, month: parseFloat(month) || 0, year: parseFloat(year) || 0 };
    update({ budgets, budget: budgets.month });
  };
  const Field = ({ label, val, setVal }) => (
    <div className="flex items-center justify-between gap-2">
      <span className="text-sm text-gray-600 font-medium">{label}</span>
      <div className="flex items-center gap-1 px-3 py-2 rounded-xl bg-gray-50" style={{ width: 150 }}>
        <span className="text-gray-400 text-sm">S$</span>
        <input inputMode="decimal" value={val} onChange={(e) => setVal(e.target.value.replace(/[^\d.]/g, ''))}
          placeholder="0.00" className="w-full bg-transparent outline-none tnum text-sm" />
      </div>
    </div>
  );
  return (
    <div className="space-y-3">
      <div className="text-xs text-gray-400">All optional — leave any blank if you don't budget for it. Set ones show a progress bar in Insights for that period.</div>
      <Field label="Weekly" val={week} setVal={setWeek} />
      <Field label="Monthly" val={month} setVal={setMonth} />
      <Field label="Yearly" val={year} setVal={setYear} />
      <button onClick={save}
        className="w-full px-4 py-2.5 rounded-xl text-white text-sm font-medium" style={{ background: ACCENT }}>Save budgets</button>
    </div>
  );
}

function DataTools({ data, setData }) {
  const fileRef = useRef(null);

  const dl = (content, type, fname) => {
    const blob = new Blob([content], { type });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = fname; a.click();
    URL.revokeObjectURL(url);
  };

  const exportCSV = () => {
    const head = ['Date', 'Description', 'Category', 'Sub', 'Amount', 'Currency', 'SGD', 'Trip'];
    const catName = (id) => data.categories.find((c) => c.id === id)?.name || '';
    const subName = (id, sid) => data.categories.find((c) => c.id === id)?.subs.find((s) => s.id === sid)?.name || '';
    const tripName = (id) => data.trips.find((t) => t.id === id)?.name || '';
    const rows = data.expenses.map((e) => [
      e.date, '"' + (e.desc || '').replace(/"/g, '""') + '"', catName(e.catId), subName(e.catId, e.subId),
      e.original, e.currency, e.sgd.toFixed(2), tripName(e.tripId),
    ].join(','));
    dl([head.join(','), ...rows].join('\n'), 'text/csv', 'expenses.csv');
  };

  const exportJSON = () => dl(JSON.stringify(data, null, 2), 'application/json', 'expense-backup.json');

  const importJSON = (ev) => {
    const f = ev.target.files?.[0];
    if (!f) return;
    const r = new FileReader();
    r.onload = () => {
      try {
        const parsed = JSON.parse(r.result);
        if (parsed.expenses && parsed.categories) setData(parsed);
      } catch (e) { /* ignore bad file */ }
    };
    r.readAsText(f);
  };

  const reset = () => {
    if (confirm('Erase all expenses, trips and settings? This cannot be undone.')) setData(seedData());
  };

  return (
    <div className="space-y-2">
      <button onClick={exportCSV} className="w-full flex items-center gap-2 px-3 py-2.5 rounded-xl bg-gray-50 text-sm font-medium">
        <Download size={16} className="text-gray-400" /> Export as CSV (for Excel / Sheets)
      </button>
      <button onClick={exportJSON} className="w-full flex items-center gap-2 px-3 py-2.5 rounded-xl bg-gray-50 text-sm font-medium">
        <Download size={16} className="text-gray-400" /> Download full backup
      </button>
      <button onClick={() => fileRef.current?.click()} className="w-full flex items-center gap-2 px-3 py-2.5 rounded-xl bg-gray-50 text-sm font-medium">
        <Upload size={16} className="text-gray-400" /> Restore from backup
      </button>
      <input ref={fileRef} type="file" accept="application/json" onChange={importJSON} className="hidden" />
      <button onClick={reset} className="w-full flex items-center gap-2 px-3 py-2.5 rounded-xl bg-red-50 text-red-500 text-sm font-medium">
        <RotateCcw size={16} /> Reset everything
      </button>
    </div>
  );
}

